        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, []);

  // --- AI SIMULATION LOGIC ---
  const runSimulation = async (triggerPost: Post) => {
    if (isSimulating) return; // Prevent overlapping simulations
    setIsSimulating(true);

    try {
        console.log("Echo: Initiating simulation...");
        const response = await simulateSocialActivity(posts, triggerPost);
