        // 1. Process Reactions (Comments/Likes) on the user's post
        if (response.reactionsToPost && response.reactionsToPost.comments) {
             const { comments, likesToAdd } = response.reactionsToPost;

             // Add a slight delay for realism
             await new Promise(r => setTimeout(r, 2000));

             // Post comments
