                 await SupabaseService.toggleLike(triggerPost.id, true);
             }
        }

        // 2. Process New Background Posts
        if (response.newPosts && response.newPosts.length > 0) {
            await new Promise(r => setTimeout(r, 1500));
            for (const newPost of response.newPosts) {
                await SupabaseService.createPost(newPost.authorName, newPost.content, newPost.tags);
            }
        }

    } catch (e) {
        // Log clean error
        console.error("Echo: Simulation glitch", getErrorMessage(e));
    } finally {
        setIsSimulating(false);
    }
  };

