                        <h3 className="font-bold text-sm">Connection Error</h3>
                        <p className="text-xs opacity-90 font-mono break-all">{errorMsg}</p>
                        {/* Prompt for schema fix */}
                        {(errorMsg.includes("column") && errorMsg.includes("does not exist")) && (
                            <div className="mt-3 p-2 bg-white/50 dark:bg-black/20 rounded border border-red-200 dark:border-red-800/50 text-xs">
                                <strong>Tip:</strong> Your database tables are missing columns (likely <code>nickname</code>). Click the button below to copy the SQL repair script, then run it in your Supabase SQL Editor.
                            </div>
                        )}
                        <button 
                            onClick={copySQL}
                            className="mt-2 text-xs bg-white dark:bg-black px-3 py-1.5 rounded-lg border border-red-100 dark:border-red-900/30 font-medium flex items-center gap-2 w-fit hover:border-red-300 transition-colors"
                        >
                            {copied ? <Check size={12} className="text-green-500" /> : <Database size={12} />}
                            {copied ? 'SQL Copied' : 'Copy SQL Fix'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Debug / Status Panel */}
        {showDebug && (
            <div className="mb-8 p-6 rounded-[32px] bg-white dark:bg-[#0F0F0F] border border-neutral-200 dark:border-neutral-800 shadow-sm">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-lg">System Status</h3>
                    <div className={`flex items-center gap-2 text-xs font-bold px-3 py-1 rounded-full bg-neutral-100 dark:bg-neutral-800 ${statusColor}`}>
                        <div className="w-2 h-2 rounded-full bg-current animate-pulse" />
                        {authUserId && !authUserId.includes('-') && authUserId.length > 30 ? 'AUTHENTICATED' : 'SHADOW MODE'}
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-1">User ID</div>
                        <code className="text-xs font-mono bg-neutral-100 dark:bg-black px-2 py-1 rounded block overflow-hidden text-ellipsis">{authUserId || 'Loading...'}</code>
                    </div>
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-2">Actions</div>
                        <button 
                            onClick={copySQL}
                            className="text-xs flex items-center gap-2 px-4 py-2 bg-black text-white dark:bg-white dark:text-black rounded-full font-medium active:scale-95 transition-transform"
                        >
                            <Terminal size={14} />
                            {copied ? 'Copied to Clipboard' : 'Copy Database Setup SQL'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Input Area (Hidden if filtering) */}
        {!activeFilter && !isAuthLoading && (
            <>
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                {/* Trending Scroll */}
                <div className="flex items-center gap-2 overflow-x-auto pb-4 pt-2 no-scrollbar mask-gradient">
                    <div className="flex items-center gap-2 pr-4">
                        <Sparkles size={14} className="text-neutral-400" />
                        <span className="text-xs font-bold text-neutral-400 uppercase tracking-wider whitespace-nowrap">Trending:</span>
                    </div>
                    {trendingTopics.map((topic, i) => (
                        <button
                            key={i}
                            onClick={() => handleTagClick(topic)}
                            className="px-3 py-1.5 rounded-full bg-white border border-neutral-200 text-xs font-medium text-neutral-600 hover:border-black hover:text-black whitespace-nowrap transition-all
                                       dark:bg-[#111] dark:border-neutral-800 dark:text-neutral-400 dark:hover:border-white dark:hover:text-white"
                        >
                            {topic}
                        </button>
                    ))}
                </div>
            </>
        )}

        {/* Active Filter Banner */}
        {activeFilter && (
            <div className="mb-6 flex items-center justify-between p-1 pl-1 pr-4 rounded-full bg-black text-white dark:bg-white dark:text-black animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-full bg-white/20 dark:bg-black/10">
                        {activeFilter.type === 'tag' ? <Hash size={20} /> : <AtSign size={20} />}
                    </div>
                    <div>
                        <div className="text-[10px] uppercase font-bold opacity-60 tracking-wider">
                            {activeFilter.type === 'tag' ? 'Viewing Tag' : 'Viewing User'}
                        </div>
                        <h3 className="font-bold text-sm">
                            {activeFilter.type === 'tag' ? `#${activeFilter.value}` : activeFilter.value}
                        </h3>
                    </div>
                </div>
                <button onClick={clearFilter} className="p-2 rounded-full hover:bg-white/20 dark:hover:bg-black/10 transition-colors">
                    <X size={18} />
                </button>
            </div>
        )}

        {/* Feed */}
        <div className="space-y-4 min-h-[50vh]">
            {(isLoading || isAuthLoading) && posts.length === 0 ? (
                 <div className="flex flex-col items-center justify-center py-20 opacity-50 space-y-4">
                    <div className="w-8 h-8 border-2 border-current border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-sm font-medium">Loading feed...</p>
                 </div>
            ) : filteredPosts.length === 0 ? (
                <div className="text-center py-20 opacity-60">
                    <div className="text-4xl mb-4 grayscale flex justify-center">
                        {activeFilter ? (activeFilter.type === 'tag' ? '🔭' : '👤') : '🎙️'}
                    </div>
                    <h2 className="text-lg font-medium mb-1">
                        {activeFilter ? 'No signals found' : 'Echo is quiet'}
                    </h2>
                    <p className="text-sm text-neutral-500">
                        {activeFilter 
                            ? (activeFilter.type === 'tag' ? `Be the first to tag #${activeFilter.value}` : `No posts from ${activeFilter.value} yet`)
                            : 'Start the conversation'}
                    </p>
                    {activeFilter && (
                        <button onClick={clearFilter} className="mt-4 text-sm font-bold underline hover:text-black dark:hover:text-white">
                            View All Posts
                        </button>
                    )}
                </div>
            ) : (
                filteredPosts.map(post => (
                    <PostCard 
                        key={post.id} 
                        post={post} 
                        isUser={isOwner(post)} 
                        onDelete={handleDeletePost}
                        onTagClick={handleTagClick}
                        onUserClick={handleUserClick}
                    />
                ))
            )}
        </div>

        {/* Footer */}
        <footer className="mt-20 py-8 border-t border-neutral-100 dark:border-white/5 flex flex-col items-center gap-4 text-neutral-400">
            {isSimulating ? (
                <div className="flex items-center gap-2 text-xs font-bold text-purple-500 animate-pulse">
                     <Zap size={12} className="fill-current" />
                     Echo is Responding...
                </div>
            ) : (
                <div className="flex items-center gap-2 text-xs font-medium">
                    <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                    Live Connection
                </div>
            )}
            <p className="text-[10px] uppercase tracking-widest opacity-50">
                Echo • Decentralized Feed Experiment
            </p>
        </footer>

      </main>
    </div>
  );
}

import React, { useState } from 'react';
import { Send, Hash, AtSign } from 'lucide-react';

interface CreatePostProps {
  onPost: (nickname: string, content: string, tags: string[]) => void;
  defaultNickname: string;
}

export const CreatePost: React.FC<CreatePostProps> = ({ onPost, defaultNickname }) => {
  const [nickname, setNickname] = useState(defaultNickname);
  const [content, setContent] = useState('');
  const [tagInput, setTagInput] = useState('');
  const [isFocused, setIsFocused] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!nickname.trim() || !content.trim()) return;

    // 1. Tags from dedicated input (split by space or comma)
    const explicitTags = tagInput
        .split(/[\s,]+/)
        .map(t => t.trim().replace(/^#/, ''))
        .filter(t => t.length > 0);

    // 2. Tags embedded in content (hashtags)
    const contentTags = content.match(/#[\w]+/g)?.map(t => t.replace('#', '')) || [];

    // Merge and de-duplicate
    const finalTags = [...new Set([...explicitTags, ...contentTags])];

    onPost(nickname, content, finalTags);

    // Reset form
    setContent('');
    setTagInput('');
    // We keep focus state if user wants to post again immediately, 
    // or we can let the blur handler below handle it naturally.
    // Ideally, we reset focus state only if they click away.
    // For now, let's keep it expanded if they hover, but usually reset is cleaner.
    // However, to prevent UI jumping, we leave isFocused true until they click away.
  };

  const handleFocus = () => setIsFocused(true);

  const handleBlur = (e: React.FocusEvent) => {
    // Check if the new focus target is still inside this component
    if (e.currentTarget.contains(e.relatedTarget)) {
      return;
    }
    // Only collapse if fields are empty
    if (!content.trim() && !tagInput.trim()) {
      setIsFocused(false);
    }
  };

  const isExpanded = isFocused || content.length > 0 || tagInput.length > 0;

  return (
    <div 
        onFocus={handleFocus}
        onBlur={handleBlur}
        className={`
            relative overflow-hidden transition-all duration-300
            bg-white dark:bg-[#0F0F0F] 
            rounded-[32px] 
            ${isExpanded 
                ? 'shadow-xl shadow-black/5 ring-1 ring-black/5 dark:shadow-white/5 dark:ring-white/10 p-6 mb-8' 
                : 'shadow-sm border border-neutral-200 dark:border-neutral-800 p-4 mb-6 hover:border-neutral-300 dark:hover:border-neutral-700'
            }
        `}
    >
      <form onSubmit={handleSubmit}>

        {/* Top Row: Nickname Identity */}
        <div className={`flex items-center gap-3 transition-all duration-300 ${isExpanded ? 'mb-4' : 'mb-2 opacity-60'}`}>
            <div className="flex items-center gap-2 px-3 py-1.5 bg-neutral-100 dark:bg-[#1A1A1A] rounded-full group hover:ring-1 hover:ring-black/5 dark:hover:ring-white/10 transition-all">
                <AtSign size={14} className="text-neutral-500 group-hover:text-black dark:group-hover:text-white" />
                <input
                    type="text"
                    value={nickname}
                    onChange={(e) => setNickname(e.target.value)}
                    placeholder="Anonymous"
                    className="bg-transparent border-none outline-none text-xs font-bold text-neutral-900 dark:text-neutral-100 w-24 placeholder-neutral-400"
                    required
                />
            </div>
            {isExpanded && (
                <span className="text-[10px] font-medium text-neutral-400 uppercase tracking-wide animate-in fade-in">
                    Posting as
                </span>
            )}
        </div>

        {/* Text Area */}
        <div className="relative">
          <textarea
            value={content}
            onChange={(e) => setContent(e.target.value)}
            placeholder="What's happening?"
            className={`
                w-full bg-transparent border-none focus:ring-0 resize-none 
                text-lg leading-relaxed
                text-neutral-900 placeholder-neutral-400
                dark:text-white dark:placeholder-neutral-600
                ${isExpanded ? 'min-h-[100px]' : 'min-h-[60px]'}
                transition-all duration-300
            `}
            required
          />
        </div>

        {/* Tag Input Section - Visible when expanded */}
        <div className={`
            mt-2 pt-3 border-t border-neutral-100 dark:border-white/5
            transition-all duration-300 origin-top
            ${isExpanded ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 h-0 overflow-hidden border-none pt-0'}
        `}>
            <div className="flex items-center gap-3 text-neutral-400 focus-within:text-black dark:focus-within:text-white transition-colors">
                <Hash size={16} className="shrink-0" />
                <input 
                    type="text"
                    value={tagInput}
                    onChange={(e) => setTagInput(e.target.value)}
                    placeholder="topics, interests, vibes (space separated)..."
                    className="w-full bg-transparent border-none outline-none text-sm font-medium text-neutral-700 dark:text-neutral-300 placeholder-neutral-300 dark:placeholder-neutral-700"
                />
            </div>
        </div>

        {/* Bottom Action Bar */}
        <div className={`
            flex justify-end items-center mt-4
            transition-all duration-300 origin-top
            ${isExpanded ? 'opacity-100 translate-y-0' : 'opacity-0 -translate-y-4 h-0 overflow-hidden mt-0'}
        `}>
          <button 
            type="submit" 
            disabled={!content.trim() || !nickname.trim()}
            className="
                group flex items-center gap-2 px-6 py-2.5 rounded-full font-bold text-sm transition-all duration-200
                bg-black text-white hover:bg-neutral-800 disabled:opacity-50 disabled:cursor-not-allowed
                dark:bg-white dark:text-black dark:hover:bg-neutral-200
            "
          >
            <span>Post</span>
            <Send size={16} className="group-hover:translate-x-1 transition-transform" />
          </button>
        </div>
      </form>
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, RefreshCw, Check, Hash, X, Info, Shield, ShieldAlert, Sparkles, User, AtSign, Zap } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import * as SupabaseService from './services/supabaseClient';

type FilterState = { type: 'tag' | 'user'; value: string } | null;

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  const [activeFilter, setActiveFilter] = useState<FilterState>(null);

  const [showDebug, setShowDebug] = useState(false);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    // Supabase standard error object
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    // Handle raw objects (prevent [object Object])
    if (typeof e === 'object') return JSON.stringify(e);
    return String(e);
  };

  const loadPosts = async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      // Only set generic error if we really have no data
      if (posts.length === 0) {
        const msg = getErrorMessage(e);
        setErrorMsg(msg);
        // Auto-show debug if it's a schema error
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  };

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      // Refresh on any insert or delete in posts OR comments
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, []);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    setPosts(prev => prev.filter(p => p.id !== postId));

    if (!postId.includes('-') && /^\d+$/.test(postId)) return;

    try {
        await SupabaseService.deletePost(postId);
    } catch (e: any) {
        console.error("Delete failed", e);
        alert(`Failed to delete. You might not be the owner.\n\n${getErrorMessage(e)}`);
        loadPosts();
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    const sql = `
-- 1. Tables & Columns (Idempotent Migration)
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table posts add column if not exists nickname text;
alter table posts add column if not exists content text;
alter table posts add column if not exists tags text[] default '{}';
alter table posts add column if not exists likes int default 0;
alter table posts add column if not exists avatar_seed text;
alter table posts add column if not exists user_id uuid;

create table if not exists comments (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table comments add column if not exists post_id uuid references posts(id) on delete cascade;
alter table comments add column if not exists user_id uuid;
-- FIX: Ensure nickname exists
alter table comments add column if not exists nickname text;
alter table comments add column if not exists avatar_seed text;
alter table comments add column if not exists content text;
alter table comments add column if not exists body text;
-- Legacy compatibility: make body nullable if we prefer content
alter table comments alter column body drop not null;

-- 2. Indexes & RLS
create index if not exists idx_posts_user_id on posts(user_id);
create index if not exists idx_comments_post_id on comments(post_id);

alter table posts enable row level security;
alter table comments enable row level security;

-- 3. Automatic User ID Trigger
create or replace function set_user_id()
returns trigger as $$
begin
  if auth.uid() is not null then
    new.user_id := auth.uid();
  elsif current_setting('request.headers', true)::json->>'x-shadow-user-id' is not null then
    new.user_id := (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid;
  end if;
  return new;
end;
$$ language plpgsql;

drop trigger if exists set_user_id_posts on posts;
create trigger set_user_id_posts before insert on posts for each row execute function set_user_id();

drop trigger if exists set_user_id_comments on comments;
create trigger set_user_id_comments before insert on comments for each row execute function set_user_id();

-- 4. Policies (Refresh)
drop policy if exists "Universal Read" on posts;
drop policy if exists "Universal Insert" on posts;
drop policy if exists "Universal Delete" on posts;
drop policy if exists "Universal Read Comments" on comments;
drop policy if exists "Universal Insert Comments" on comments;
drop policy if exists "Universal Delete Comments" on comments;

create policy "Universal Read" on posts for select using (true);
create policy "Universal Insert" on posts for insert with check (true);
create policy "Universal Delete" on posts for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);

create policy "Universal Read Comments" on comments for select using (true);
create policy "Universal Insert Comments" on comments for insert with check (true);
create policy "Universal Delete Comments" on comments for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
`;
    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
      setActiveFilter({ type: 'tag', value: rawTag });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUserClick = (nickname: string) => {
      setActiveFilter({ type: 'user', value: nickname });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const clearFilter = () => setActiveFilter(null);

  const filteredPosts = useMemo(() => {
      if (!activeFilter) return posts;
      if (activeFilter.type === 'tag') {
          return posts.filter(post => 
              post.tags.some(t => t.toLowerCase() === activeFilter.value.toLowerCase())
          );
      }
      if (activeFilter.type === 'user') {
          return posts.filter(post => post.author.nickname === activeFilter.value);
      }
      return posts;
  }, [posts, activeFilter]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => {
        if (post.tags && Array.isArray(post.tags)) {
            post.tags.forEach(tag => {
                if(tag) counts[tag] = (counts[tag] || 0) + 1;
            });
        }
    });
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    // Only return real tags, no demo data fallback
    return sorted.slice(0, 10).map(t => '#' + t[0]);
  }, [posts]);

  const isOwner = (post: Post) => {
    if (!authUserId) return false;
    return post.author.userId === authUserId;
  };

  const statusColor = authUserId && !authUserId.includes('-') && authUserId.length > 30
      ? 'text-green-500' 
      : 'text-yellow-500';

  return (
    <div className="min-h-screen transition-colors duration-300 bg-[#FAFAFA] text-neutral-900 dark:bg-[#050505] dark:text-white">

      {/* Sticky Header */}
      <header className="sticky top-0 z-30 w-full backdrop-blur-xl bg-white/80 dark:bg-black/80 border-b border-neutral-200 dark:border-white/10">
        <div className="max-w-2xl mx-auto px-4 h-16 flex items-center justify-between">
            <div 
                onClick={() => { clearFilter(); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
                className="flex items-center gap-2 cursor-pointer group"
            >
                <div className="w-8 h-8 bg-black dark:bg-white rounded-xl flex items-center justify-center text-white dark:text-black font-bold text-lg shadow-sm transition-transform group-hover:scale-105">
                    E
                </div>
                <span className="font-bold text-xl tracking-tight">Echo</span>
            </div>

            <div className="flex items-center gap-3">
                <button 
                    onClick={() => setShowDebug(!showDebug)}
                    className={`p-2 rounded-full transition-colors ${showDebug ? 'bg-neutral-100 dark:bg-white/10 text-black dark:text-white' : 'text-neutral-400 hover:text-black dark:hover:text-white'}`}
                >
                    <Info size={20} />
                </button>
                <button 
                    onClick={toggleTheme} 
                    className="p-2 rounded-full text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-white/10 transition-colors"
                >
                    {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                </button>
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-2xl mx-auto px-4 py-8">

        {/* Error Banner */}
        {errorMsg && (
            <div className="mb-8 p-4 rounded-2xl border border-red-200 bg-red-50 text-red-800 dark:border-red-900/50 dark:bg-red-900/20 dark:text-red-200 shadow-sm animate-in slide-in-from-top-4">
                <div className="flex items-start gap-3">
                    <XCircle className="shrink-0 mt-0.5" size={20} />
                    <div className="space-y-2 w-full">
