import React, { useState, useEffect, useRef } from 'react';
import { Heart, MessageCircle, MoreVertical, Trash2, Send, X } from 'lucide-react';
import { Post, Comment } from '../types';
import { DEFAULT_AVATAR_URL } from '../constants';
import { toggleLike, createComment, deleteComment, getEffectiveUserId } from '../services/supabaseClient';

interface PostCardProps {
  post: Post;
  isUser: boolean;
  onDelete?: (id: string) => void;
  onTagClick?: (tag: string) => void;
  onUserClick?: (nickname: string) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, isUser, onDelete, onTagClick, onUserClick }) => {
  const [liked, setLiked] = useState(false);
  const [optimisticLikes, setOptimisticLikes] = useState(post.likes);
  const [isDeleting, setIsDeleting] = useState(false);

  // Comment State
  const [showComments, setShowComments] = useState(false);
  const [comments, setComments] = useState<Comment[]>(post.comments || []);
  const [newCommentText, setNewCommentText] = useState('');
  const [isSubmittingComment, setIsSubmittingComment] = useState(false);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);

  // Sync props to state if post updates from parent (real-time)
  useEffect(() => {
    setComments(post.comments || []);
  }, [post.comments]);

  useEffect(() => {
    getEffectiveUserId().then(setCurrentUserId);
  }, []);

  const handleLike = () => {
    const isLiking = !liked;
    setLiked(isLiking);
    setOptimisticLikes(prev => isLiking ? prev + 1 : prev - 1);
    toggleLike(post.id, isLiking);
  };

  const handleDelete = () => {
    if (confirm('Are you sure you want to delete this post?') && onDelete) {
      setIsDeleting(true);
      onDelete(post.id);
    }
  };

  const handleTagClick = (tag: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (onTagClick) onTagClick(tag);
  };

  const handleUserClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onUserClick) onUserClick(post.author.nickname);
  }

  const toggleComments = () => {
    setShowComments(!showComments);
  };

  const handleSubmitComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCommentText.trim()) return;

    const text = newCommentText;
    setNewCommentText(''); // Clear input immediately
    setIsSubmittingComment(true);

    // Get current user nickname from local storage for optimistic update
    const nickname = localStorage.getItem('echo_nickname') || 'Guest';

    // Optimistic Comment
    const tempId = 'temp-' + Date.now();
    const optimisticComment: Comment = {
      id: tempId,
      author: {
        nickname,
        avatarSeed: nickname,
        isAi: false,
        userId: currentUserId || ''
      },
      content: text,
      timestamp: Date.now(),
      likes: 0
    };

    setComments(prev => [...prev, optimisticComment]);
    if (!showComments) setShowComments(true);

    try {
      const realComment = await createComment(post.id, text, nickname);
      // Replace optimistic comment with real one
      setComments(prev => prev.map(c => c.id === tempId ? realComment : c));
    } catch (err) {
      console.error("Failed to submit comment", err);
      alert("Failed to post comment. Please try again.");
      setComments(prev => prev.filter(c => c.id !== tempId));
      setNewCommentText(text); // Restore text
    } finally {
      setIsSubmittingComment(false);
    }
  };

  const handleDeleteComment = async (commentId: string) => {
    if (!confirm("Delete this comment?")) return;

    const previousComments = [...comments];
    setComments(prev => prev.filter(c => c.id !== commentId));

    try {
      await deleteComment(commentId);
    } catch (err) {
      console.error("Failed to delete comment", err);
      alert("Could not delete comment.");
      setComments(previousComments);
    }
  };

  const formattedTime = new Intl.DateTimeFormat('en-US', {
    hour: 'numeric',
    minute: 'numeric',
  }).format(new Date(post.timestamp));

  if (isDeleting) {
    return (
        <div className="p-5 mb-4 rounded-[24px] border border-red-200 bg-red-50 text-red-500 flex items-center justify-center dark:border-red-900/50 dark:bg-red-900/10">
            <span className="text-sm font-medium animate-pulse">Deleting...</span>
        </div>
    );
  }

  return (
    <div className={`
      relative p-5 mb-4 transition-all duration-300
      rounded-[24px] border
      ${isUser 
        ? 'bg-neutral-100 border-neutral-200 text-black dark:bg-[#1A1A1A] dark:border-neutral-700 dark:text-white' 
        : 'bg-white border-neutral-200 text-neutral-800 dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-300' 
      }
    `}>
      {/* Header */}
      <div className="flex items-start justify-between mb-4">
        <div 
            onClick={handleUserClick}
            className="flex items-center gap-4 group cursor-pointer"
        >
          <img 
            src={DEFAULT_AVATAR_URL(post.author.avatarSeed)} 
            alt={post.author.nickname}
            className="w-10 h-10 rounded-full object-cover grayscale opacity-80 group-hover:grayscale-0 group-hover:scale-105 transition-all border border-neutral-200 dark:border-neutral-800" 
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`text-base font-medium tracking-wide group-hover:underline ${isUser ? 'text-black dark:text-white' : 'text-neutral-900 dark:text-neutral-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-black text-white dark:bg-white dark:text-black font-bold tracking-wider">
                  BOT
                </span>
              )}
            </div>
            <span className="text-xs text-neutral-500 dark:text-neutral-500">{formattedTime}</span>
          </div>
        </div>

        {isUser && (
           <button 
             onClick={handleDelete}
             className="text-neutral-400 hover:text-red-600 dark:text-neutral-500 dark:hover:text-red-400 rounded-full p-2 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
             title="Delete Post"
           >
             <Trash2 size={18} />
           </button>
        )}
      </div>

      {/* Content */}
      <div className="mb-4 pl-[56px]">
        <p className="text-base leading-relaxed tracking-wide opacity-90 text-neutral-800 dark:text-neutral-200 whitespace-pre-wrap">
          {post.content}
        </p>
        {post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-4">
            {post.tags.map(tag => (
              <span 
                key={tag} 
                onClick={(e) => handleTagClick(tag, e)}
                className="px-3 py-1 rounded-lg text-xs font-medium transition-colors cursor-pointer
                           bg-neutral-100 border border-neutral-200 text-neutral-600 hover:bg-neutral-200 hover:text-black hover:border-neutral-300
                           dark:bg-neutral-900 dark:border-neutral-800 dark:text-neutral-400 dark:hover:text-white dark:hover:border-neutral-600"
              >
                #{tag.replace(/^#/, '')}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-6 pl-[56px] pt-1">
        <button 
          onClick={handleLike}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors 
            ${liked 
              ? 'text-black dark:text-white' 
              : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-neutral-300'
            }`}
        >
          <div className={`p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors`}>
             <Heart size={20} fill={liked ? "currentColor" : "none"} className={liked ? "scale-110" : ""} />
          </div>
          <span>{optimisticLikes}</span>
        </button>

        <button 
          onClick={toggleComments}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors
            ${showComments ? 'text-black dark:text-white' : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-white'}
          `}
        >
          <div className="p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors">
             <MessageCircle size={20} />
          </div>
          <span>{comments.length}</span>
        </button>
      </div>

      {/* Comments Section */}
      {showComments && (
        <div className="mt-4 pt-4 pl-[56px] border-t border-neutral-100 dark:border-neutral-800 animate-in fade-in slide-in-from-top-2 duration-200">

          {/* Add Comment Input */}
          <form onSubmit={handleSubmitComment} className="flex gap-3 mb-6">
             <img 
                src={DEFAULT_AVATAR_URL(localStorage.getItem('echo_nickname') || 'Guest')} 
                className="w-8 h-8 rounded-full grayscale opacity-50"
             />
             <div className="flex-1 relative">
                <input 
                  type="text" 
                  value={newCommentText}
                  onChange={(e) => setNewCommentText(e.target.value)}
                  placeholder="Write a reply..."
                  className="w-full bg-neutral-50 dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 rounded-full py-2 px-4 text-sm focus:outline-none focus:border-black dark:focus:border-white transition-colors"
                />
                <button 
                  type="submit" 
                  disabled={!newCommentText.trim() || isSubmittingComment}
                  className="absolute right-2 top-1.5 p-1 rounded-full text-black dark:text-white hover:bg-neutral-200 dark:hover:bg-neutral-700 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                >
                  <Send size={14} />
                </button>
             </div>
          </form>

          {/* Comment List */}
          <div className="space-y-5">
            {comments.map(comment => (
              <div key={comment.id} className="flex gap-3 group/comment">
                <img 
                  src={DEFAULT_AVATAR_URL(comment.author.avatarSeed)} 
                  alt={comment.author.nickname}
                  className="w-8 h-8 rounded-full grayscale opacity-70"
                />
                <div className="flex-1">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-sm font-bold text-neutral-900 dark:text-neutral-200">{comment.author.nickname}</span>
                      <span className="text-[10px] text-neutral-400 dark:text-neutral-600">
                        {new Intl.DateTimeFormat('en-US', { hour: 'numeric', minute: 'numeric' }).format(new Date(comment.timestamp))}
                      </span>
                    </div>

                    {currentUserId === comment.author.userId && (
                      <button 
                        onClick={() => handleDeleteComment(comment.id)}
                        className="opacity-0 group-hover/comment:opacity-100 transition-opacity p-1 text-neutral-400 hover:text-red-500"
                      >
                        <Trash2 size={12} />
                      </button>
                    )}
                  </div>
                  <p className="text-sm text-neutral-600 dark:text-neutral-400 leading-relaxed">{comment.content}</p>
                </div>
              </div>
            ))}

            {comments.length === 0 && (
                <div className="text-center py-4 opacity-40 text-xs italic">
                    No comments yet. Start the conversation.
                </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, RefreshCw, Check, Hash, X, Info, Shield, ShieldAlert, Sparkles, User, AtSign, Zap } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import * as SupabaseService from './services/supabaseClient';

type FilterState = { type: 'tag' | 'user'; value: string } | null;

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  const [activeFilter, setActiveFilter] = useState<FilterState>(null);

  const [showDebug, setShowDebug] = useState(false);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    // Supabase standard error object
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    // Handle raw objects (prevent [object Object])
    if (typeof e === 'object') return JSON.stringify(e);
    return String(e);
  };

  const loadPosts = async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      // Only set generic error if we really have no data
      if (posts.length === 0) {
        const msg = getErrorMessage(e);
        setErrorMsg(msg);
        // Auto-show debug if it's a schema error
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  };

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      // Refresh on any insert or delete in posts OR comments
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, []);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    setPosts(prev => prev.filter(p => p.id !== postId));

    if (!postId.includes('-') && /^\d+$/.test(postId)) return;

    try {
        await SupabaseService.deletePost(postId);
    } catch (e: any) {
        console.error("Delete failed", e);
        alert(`Failed to delete. You might not be the owner.\n\n${getErrorMessage(e)}`);
        loadPosts();
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    const sql = `
-- 1. Tables & Columns (Idempotent Migration)
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table posts add column if not exists nickname text;
alter table posts add column if not exists content text;
alter table posts add column if not exists tags text[] default '{}';
alter table posts add column if not exists likes int default 0;
alter table posts add column if not exists avatar_seed text;
alter table posts add column if not exists user_id uuid;

create table if not exists comments (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table comments add column if not exists post_id uuid references posts(id) on delete cascade;
alter table comments add column if not exists user_id uuid;
-- FIX: Ensure nickname exists
alter table comments add column if not exists nickname text;
alter table comments add column if not exists avatar_seed text;
alter table comments add column if not exists content text;
alter table comments add column if not exists body text;
-- Legacy compatibility: make body nullable if we prefer content
alter table comments alter column body drop not null;

-- 2. Indexes & RLS
create index if not exists idx_posts_user_id on posts(user_id);
create index if not exists idx_comments_post_id on comments(post_id);

alter table posts enable row level security;
alter table comments enable row level security;

-- 3. Automatic User ID Trigger
create or replace function set_user_id()
returns trigger as $$
begin
  if auth.uid() is not null then
    new.user_id := auth.uid();
  elsif current_setting('request.headers', true)::json->>'x-shadow-user-id' is not null then
    new.user_id := (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid;
  end if;
  return new;
end;
$$ language plpgsql;

drop trigger if exists set_user_id_posts on posts;
create trigger set_user_id_posts before insert on posts for each row execute function set_user_id();

drop trigger if exists set_user_id_comments on comments;
create trigger set_user_id_comments before insert on comments for each row execute function set_user_id();

-- 4. Policies (Refresh)
drop policy if exists "Universal Read" on posts;
drop policy if exists "Universal Insert" on posts;
drop policy if exists "Universal Delete" on posts;
drop policy if exists "Universal Read Comments" on comments;
drop policy if exists "Universal Insert Comments" on comments;
drop policy if exists "Universal Delete Comments" on comments;

create policy "Universal Read" on posts for select using (true);
create policy "Universal Insert" on posts for insert with check (true);
create policy "Universal Delete" on posts for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);

create policy "Universal Read Comments" on comments for select using (true);
create policy "Universal Insert Comments" on comments for insert with check (true);
create policy "Universal Delete Comments" on comments for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
`;
    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
      setActiveFilter({ type: 'tag', value: rawTag });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUserClick = (nickname: string) => {
      setActiveFilter({ type: 'user', value: nickname });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const clearFilter = () => setActiveFilter(null);

  const filteredPosts = useMemo(() => {
      if (!activeFilter) return posts;
      if (activeFilter.type === 'tag') {
          return posts.filter(post => 
              post.tags.some(t => t.toLowerCase() === activeFilter.value.toLowerCase())
          );
      }
      if (activeFilter.type === 'user') {
          return posts.filter(post => post.author.nickname === activeFilter.value);
      }
      return posts;
  }, [posts, activeFilter]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => {
        if (post.tags && Array.isArray(post.tags)) {
            post.tags.forEach(tag => {
                if(tag) counts[tag] = (counts[tag] || 0) + 1;
            });
        }
    });
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    // Only return real tags, no demo data fallback
    return sorted.slice(0, 10).map(t => '#' + t[0]);
  }, [posts]);

  const isOwner = (post: Post) => {
    if (!authUserId) return false;
    return post.author.userId === authUserId;
  };

  const statusColor = authUserId && !authUserId.includes('-') && authUserId.length > 30
      ? 'text-green-500' 
      : 'text-yellow-500';

  return (
    <div className="min-h-screen transition-colors duration-300 bg-[#FAFAFA] text-neutral-900 dark:bg-[#050505] dark:text-white">

      {/* Sticky Header */}
      <header className="sticky top-0 z-30 w-full backdrop-blur-xl bg-white/80 dark:bg-black/80 border-b border-neutral-200 dark:border-white/10">
        <div className="max-w-2xl mx-auto px-4 h-16 flex items-center justify-between">
            <div 
                onClick={() => { clearFilter(); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
                className="flex items-center gap-2 cursor-pointer group"
            >
                <span className="font-bold text-xl tracking-tight">Echo</span>
            </div>

            <div className="flex items-center gap-3">
                <button 
                    onClick={() => setShowDebug(!showDebug)}
                    className={`p-2 rounded-full transition-colors ${showDebug ? 'bg-neutral-100 dark:bg-white/10 text-black dark:text-white' : 'text-neutral-400 hover:text-black dark:hover:text-white'}`}
                >
                    <Info size={20} />
                </button>
                <button 
                    onClick={toggleTheme} 
                    className="p-2 rounded-full text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-white/10 transition-colors"
                >
                    {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                </button>
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-2xl mx-auto px-4 py-8">

        {/* Error Banner */}
        {errorMsg && (
            <div className="mb-8 p-4 rounded-2xl border border-red-200 bg-red-50 text-red-800 dark:border-red-900/50 dark:bg-red-900/20 dark:text-red-200 shadow-sm animate-in slide-in-from-top-4">
                <div className="flex items-start gap-3">
                    <XCircle className="shrink-0 mt-0.5" size={20} />
                    <div className="space-y-2 w-full">
                        <h3 className="font-bold text-sm">Connection Error</h3>
                        <p className="text-xs opacity-90 font-mono break-all">{errorMsg}</p>
                        {/* Prompt for schema fix */}
                        {(errorMsg.includes("column") && errorMsg.includes("does not exist")) && (
                            <div className="mt-3 p-2 bg-white/50 dark:bg-black/20 rounded border border-red-200 dark:border-red-800/50 text-xs">
                                <strong>Tip:</strong> Your database tables are missing columns (likely <code>nickname</code>). Click the button below to copy the SQL repair script, then run it in your Supabase SQL Editor.
                            </div>
                        )}
                        <button 
                            onClick={copySQL}
                            className="mt-2 text-xs bg-white dark:bg-black px-3 py-1.5 rounded-lg border border-red-100 dark:border-red-900/30 font-medium flex items-center gap-2 w-fit hover:border-red-300 transition-colors"
                        >
                            {copied ? <Check size={12} className="text-green-500" /> : <Database size={12} />}
                            {copied ? 'SQL Copied' : 'Copy SQL Fix'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Debug / Status Panel */}
        {showDebug && (
            <div className="mb-8 p-6 rounded-[32px] bg-white dark:bg-[#0F0F0F] border border-neutral-200 dark:border-neutral-800 shadow-sm">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-lg">System Status</h3>
                    <div className={`flex items-center gap-2 text-xs font-bold px-3 py-1 rounded-full bg-neutral-100 dark:bg-neutral-800 ${statusColor}`}>
                        <div className="w-2 h-2 rounded-full bg-current animate-pulse" />
                        {authUserId && !authUserId.includes('-') && authUserId.length > 30 ? 'AUTHENTICATED' : 'SHADOW MODE'}
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-1">User ID</div>
                        <code className="text-xs font-mono bg-neutral-100 dark:bg-black px-2 py-1 rounded block overflow-hidden text-ellipsis">{authUserId || 'Loading...'}</code>
                    </div>
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-2">Actions</div>
                        <button 
                            onClick={copySQL}
                            className="text-xs flex items-center gap-2 px-4 py-2 bg-black text-white dark:bg-white dark:text-black rounded-full font-medium active:scale-95 transition-transform"
                        >
                            <Terminal size={14} />
                            {copied ? 'Copied to Clipboard' : 'Copy Database Setup SQL'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Input Area (Hidden if filtering) */}
        {!activeFilter && !isAuthLoading && (
            <>
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                {/* Trending Scroll - Only show if there are actual tags */}
                {trendingTopics.length > 0 && (
                    <div className="flex items-center gap-2 overflow-x-auto pb-4 pt-2 no-scrollbar mask-gradient">
                        <div className="flex items-center gap-2 pr-4">
                            <Sparkles size={14} className="text-neutral-400" />
                            <span className="text-xs font-bold text-neutral-400 uppercase tracking-wider whitespace-nowrap">Trending:</span>
                        </div>
                        {trendingTopics.map((topic, i) => (
                            <button
                                key={i}
                                onClick={() => handleTagClick(topic)}
                                className="px-3 py-1.5 rounded-full bg-white border border-neutral-200 text-xs font-medium text-neutral-600 hover:border-black hover:text-black whitespace-nowrap transition-all
                                        dark:bg-[#111] dark:border-neutral-800 dark:text-neutral-400 dark:hover:border-white dark:hover:text-white"
                            >
                                {topic}
                            </button>
                        ))}
                    </div>
                )}
            </>
        )}

        {/* Active Filter Banner */}
        {activeFilter && (
            <div className="mb-6 flex items-center justify-between p-1 pl-1 pr-4 rounded-full bg-black text-white dark:bg-white dark:text-black animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-full bg-white/20 dark:bg-black/10">
                        {activeFilter.type === 'tag' ? <Hash size={20} /> : <AtSign size={20} />}
                    </div>
                    <div>
                        <div className="text-[10px] uppercase font-bold opacity-60 tracking-wider">
                            {activeFilter.type === 'tag' ? 'Viewing Tag' : 'Viewing User'}
                        </div>
                        <h3 className="font-bold text-sm">
                            {activeFilter.type === 'tag' ? `#${activeFilter.value}` : activeFilter.value}
                        </h3>
                    </div>
                </div>
                <button onClick={clearFilter} className="p-2 rounded-full hover:bg-white/20 dark:hover:bg-black/10 transition-colors">
                    <X size={18} />
                </button>
            </div>
        )}

        {/* Feed */}
        <div className="space-y-4 min-h-[50vh]">
            {(isLoading || isAuthLoading) && posts.length === 0 ? (
                 <div className="flex flex-col items-center justify-center py-20 opacity-50 space-y-4">
                    <div className="w-8 h-8 border-2 border-current border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-sm font-medium">Loading feed...</p>
                 </div>
            ) : filteredPosts.length === 0 ? (
                <div className="text-center py-20 opacity-60">
                    <div className="text-4xl mb-4 grayscale flex justify-center">
                        {activeFilter ? (activeFilter.type === 'tag' ? '🔭' : '👤') : '🎙️'}
                    </div>
                    <h2 className="text-lg font-medium mb-1">
                        {activeFilter ? 'No signals found' : 'Echo is quiet'}
                    </h2>
                    <p className="text-sm text-neutral-500">
                        {activeFilter 
                            ? (activeFilter.type === 'tag' ? `Be the first to tag #${activeFilter.value}` : `No posts from ${activeFilter.value} yet`)
                            : 'Start the conversation'}
                    </p>
                    {activeFilter && (
                        <button onClick={clearFilter} className="mt-4 text-sm font-bold underline hover:text-black dark:hover:text-white">
                            View All Posts
                        </button>
                    )}
                </div>
            ) : (
                filteredPosts.map(post => (
                    <PostCard 
                        key={post.id} 
                        post={post} 
                        isUser={isOwner(post)} 
                        onDelete={handleDeletePost}
                        onTagClick={handleTagClick}
                        onUserClick={handleUserClick}
                    />
                ))
            )}
        </div>

        {/* Footer */}
        <footer className="mt-20 py-8 border-t border-neutral-100 dark:border-white/5 flex flex-col items-center gap-4 text-neutral-400">
            <div className="flex items-center gap-2 text-xs font-medium">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                Live Connection
            </div>
            <p className="text-[10px] uppercase tracking-widest opacity-50">
                Echo • Decentralized Feed
            </p>
        </footer>

      </main>
    </div>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import { Heart, MessageCircle, MoreVertical, Trash2, Send, X, ChevronDown, ChevronUp } from 'lucide-react';
import { Post, Comment } from '../types';
import { DEFAULT_AVATAR_URL } from '../constants';
import { toggleLike, createComment, deleteComment, getEffectiveUserId } from '../services/supabaseClient';

interface PostCardProps {
  post: Post;
  isUser: boolean;
  onDelete?: (id: string) => void;
  onTagClick?: (tag: string) => void;
  onUserClick?: (nickname: string) => void;
}

export const PostCard: React.FC<PostCardProps> = ({ post, isUser, onDelete, onTagClick, onUserClick }) => {
  const [liked, setLiked] = useState(false);
  const [optimisticLikes, setOptimisticLikes] = useState(post.likes);
  const [isDeleting, setIsDeleting] = useState(false);

  // Comment State
  const [showComments, setShowComments] = useState(false);
  const [comments, setComments] = useState<Comment[]>(post.comments || []);
  const [newCommentText, setNewCommentText] = useState('');
  const [isSubmittingComment, setIsSubmittingComment] = useState(false);
  const [currentUserId, setCurrentUserId] = useState<string | null>(null);

  // Sync props to state if post updates from parent (real-time)
  useEffect(() => {
    setComments(post.comments || []);
  }, [post.comments]);

  useEffect(() => {
    getEffectiveUserId().then(setCurrentUserId);
  }, []);

  const handleLike = () => {
    const isLiking = !liked;
    setLiked(isLiking);
    setOptimisticLikes(prev => isLiking ? prev + 1 : prev - 1);
    toggleLike(post.id, isLiking);
  };

  const handleDelete = () => {
    if (confirm('Are you sure you want to delete this post?') && onDelete) {
      setIsDeleting(true);
      onDelete(post.id);
    }
  };

  const handleTagClick = (tag: string, e: React.MouseEvent) => {
    e.stopPropagation();
    if (onTagClick) onTagClick(tag);
  };

  const handleUserClick = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onUserClick) onUserClick(post.author.nickname);
  }

  const toggleComments = () => {
    setShowComments(!showComments);
  };

  const handleSubmitComment = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCommentText.trim()) return;

    const text = newCommentText;
    setNewCommentText(''); // Clear input immediately
    setIsSubmittingComment(true);

    // Get current user nickname from local storage for optimistic update
    const nickname = localStorage.getItem('echo_nickname') || 'Guest';

    // Optimistic Comment
    const tempId = 'temp-' + Date.now();
    const optimisticComment: Comment = {
      id: tempId,
      author: {
        nickname,
        avatarSeed: nickname,
        isAi: false,
        userId: currentUserId || ''
      },
      content: text,
      timestamp: Date.now(),
      likes: 0
    };

    setComments(prev => [...prev, optimisticComment]);
    if (!showComments) setShowComments(true);

    try {
      const realComment = await createComment(post.id, text, nickname);
      // Replace optimistic comment with real one
      setComments(prev => prev.map(c => c.id === tempId ? realComment : c));
    } catch (err) {
      console.error("Failed to submit comment", err);
      alert("Failed to post comment. Please try again.");
      setComments(prev => prev.filter(c => c.id !== tempId));
      setNewCommentText(text); // Restore text
    } finally {
      setIsSubmittingComment(false);
    }
  };

  const handleDeleteComment = async (commentId: string) => {
    if (!confirm("Delete this comment?")) return;

    const previousComments = [...comments];
    setComments(prev => prev.filter(c => c.id !== commentId));

    try {
      await deleteComment(commentId);
    } catch (err) {
      console.error("Failed to delete comment", err);
      alert("Could not delete comment.");
      setComments(previousComments);
    }
  };

  const formattedTime = new Intl.DateTimeFormat('en-US', {
    hour: 'numeric',
    minute: 'numeric',
  }).format(new Date(post.timestamp));

  if (isDeleting) {
    return (
        <div className="p-5 mb-4 rounded-[24px] border border-red-200 bg-red-50 text-red-500 flex items-center justify-center dark:border-red-900/50 dark:bg-red-900/10">
            <span className="text-sm font-medium animate-pulse">Deleting...</span>
        </div>
    );
  }

  return (
    <div className={`
      relative p-5 mb-4 transition-all duration-300
      rounded-[24px] border
      ${isUser 
        ? 'bg-neutral-100 border-neutral-200 text-black dark:bg-[#1A1A1A] dark:border-neutral-700 dark:text-white' 
        : 'bg-white border-neutral-200 text-neutral-800 dark:bg-[#0A0A0A] dark:border-[#1F1F1F] dark:text-neutral-300' 
      }
    `}>
      {/* Header */}
      <div className="flex items-start justify-between mb-4">
        <div 
            onClick={handleUserClick}
            className="flex items-center gap-4 group cursor-pointer"
        >
          <img 
            src={DEFAULT_AVATAR_URL(post.author.avatarSeed)} 
            alt={post.author.nickname}
            className="w-10 h-10 rounded-full object-cover grayscale opacity-80 group-hover:grayscale-0 group-hover:scale-105 transition-all border border-neutral-200 dark:border-neutral-800" 
          />
          <div>
            <div className="flex items-center gap-2">
              <span className={`text-base font-medium tracking-wide group-hover:underline ${isUser ? 'text-black dark:text-white' : 'text-neutral-900 dark:text-neutral-200'}`}>
                {post.author.nickname}
              </span>
              {post.author.isAi && (
                <span className="text-[10px] px-2 py-0.5 rounded-full bg-black text-white dark:bg-white dark:text-black font-bold tracking-wider">
                  BOT
                </span>
              )}
            </div>
            <span className="text-xs text-neutral-500 dark:text-neutral-500">{formattedTime}</span>
          </div>
        </div>

        {isUser && (
           <button 
             onClick={handleDelete}
             className="text-neutral-400 hover:text-red-600 dark:text-neutral-500 dark:hover:text-red-400 rounded-full p-2 hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors"
             title="Delete Post"
           >
             <Trash2 size={18} />
           </button>
        )}
      </div>

      {/* Content */}
      <div className="mb-4 pl-[56px]">
        <p className="text-base leading-relaxed tracking-wide opacity-90 text-neutral-800 dark:text-neutral-200 whitespace-pre-wrap">
          {post.content}
        </p>
        {post.tags.length > 0 && (
          <div className="flex flex-wrap gap-2 mt-4">
            {post.tags.map(tag => (
              <span 
                key={tag} 
                onClick={(e) => handleTagClick(tag, e)}
                className="px-3 py-1 rounded-lg text-xs font-medium transition-colors cursor-pointer
                           bg-neutral-100 border border-neutral-200 text-neutral-600 hover:bg-neutral-200 hover:text-black hover:border-neutral-300
                           dark:bg-neutral-900 dark:border-neutral-800 dark:text-neutral-400 dark:hover:text-white dark:hover:border-neutral-600"
              >
                #{tag.replace(/^#/, '')}
              </span>
            ))}
          </div>
        )}
      </div>

      {/* Actions */}
      <div className="flex items-center gap-6 pl-[56px] pt-1">
        <button 
          onClick={handleLike}
          className={`group flex items-center gap-2 text-sm font-medium transition-colors 
            ${liked 
              ? 'text-black dark:text-white' 
              : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-neutral-300'
            }`}
        >
          <div className={`p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors`}>
             <Heart size={20} fill={liked ? "currentColor" : "none"} className={liked ? "scale-110" : ""} />
          </div>
          <span>{optimisticLikes}</span>
        </button>

        <button 
          onClick={toggleComments}
          className={`group flex items-center gap-1.5 text-sm font-medium transition-colors
            ${showComments ? 'text-black dark:text-white' : 'text-neutral-500 hover:text-black dark:text-neutral-500 dark:hover:text-white'}
          `}
        >
          <div className="p-2 rounded-full group-hover:bg-black/5 dark:group-hover:bg-white/10 transition-colors">
             <MessageCircle size={20} />
          </div>
          <span>{comments.length}</span>
          <div className="ml-1 opacity-50 group-hover:opacity-100 transition-opacity">
             {showComments ? <ChevronUp size={16} /> : <ChevronDown size={16} />}
          </div>
        </button>
      </div>

      {/* Comments Section */}
      {showComments && (
        <div className="mt-4 pt-4 pl-[56px] border-t border-neutral-100 dark:border-neutral-800 animate-in fade-in slide-in-from-top-2 duration-200">

          {/* Add Comment Input */}
          <form onSubmit={handleSubmitComment} className="flex gap-3 mb-6">
             <img 
                src={DEFAULT_AVATAR_URL(localStorage.getItem('echo_nickname') || 'Guest')} 
                className="w-8 h-8 rounded-full grayscale opacity-50"
             />
             <div className="flex-1 relative">
                <input 
                  type="text" 
                  value={newCommentText}
                  onChange={(e) => setNewCommentText(e.target.value)}
                  placeholder="Write a reply..."
                  className="w-full bg-neutral-50 dark:bg-neutral-900 border border-neutral-200 dark:border-neutral-800 rounded-full py-2 px-4 text-sm focus:outline-none focus:border-black dark:focus:border-white transition-colors"
                />
                <button 
                  type="submit" 
                  disabled={!newCommentText.trim() || isSubmittingComment}
                  className="absolute right-2 top-1.5 p-1 rounded-full text-black dark:text-white hover:bg-neutral-200 dark:hover:bg-neutral-700 disabled:opacity-30 disabled:hover:bg-transparent transition-all"
                >
                  <Send size={14} />
                </button>
             </div>
          </form>

          {/* Comment List */}
          <div className="space-y-5">
            {comments.map(comment => (
              <div key={comment.id} className="flex gap-3 group/comment">
                <img 
                  src={DEFAULT_AVATAR_URL(comment.author.avatarSeed)} 
                  alt={comment.author.nickname}
                  className="w-8 h-8 rounded-full grayscale opacity-70"
                />
                <div className="flex-1">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2 mb-0.5">
                      <span className="text-sm font-bold text-neutral-900 dark:text-neutral-200">{comment.author.nickname}</span>
                      <span className="text-[10px] text-neutral-400 dark:text-neutral-600">
                        {new Intl.DateTimeFormat('en-US', { hour: 'numeric', minute: 'numeric' }).format(new Date(comment.timestamp))}
                      </span>
                    </div>

                    {currentUserId === comment.author.userId && (
                      <button 
                        onClick={() => handleDeleteComment(comment.id)}
                        className="opacity-0 group-hover/comment:opacity-100 transition-opacity p-1 text-neutral-400 hover:text-red-500"
                      >
                        <Trash2 size={12} />
                      </button>
                    )}
                  </div>
                  <p className="text-sm text-neutral-600 dark:text-neutral-400 leading-relaxed">{comment.content}</p>
                </div>
              </div>
            ))}

            {comments.length === 0 && (
                <div className="text-center py-4 opacity-40 text-xs italic">
                    No comments yet. Start the conversation.
                </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, RefreshCw, Check, Hash, X, Info, Sparkles, User, AtSign, ArrowDown } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import * as SupabaseService from './services/supabaseClient';

type FilterState = { type: 'tag' | 'user'; value: string } | null;

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  const [activeFilter, setActiveFilter] = useState<FilterState>(null);

  const [showDebug, setShowDebug] = useState(false);

  // Pull-to-Refresh State
  const [pullDistance, setPullDistance] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const touchStartRef = useRef(0);
  const isDraggingRef = useRef(false);
  const currentPullYRef = useRef(0);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    if (typeof e === 'object') return JSON.stringify(e);
    return String(e);
  };

  const loadPosts = useCallback(async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      if (posts.length === 0) {
        const msg = getErrorMessage(e);
        setErrorMsg(msg);
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  }, [posts.length]);

  // Pull to Refresh Logic
  const loadPostsRef = useRef(loadPosts);
  useEffect(() => { loadPostsRef.current = loadPosts; }, [loadPosts]);

  useEffect(() => {
    const handleTouchStart = (e: TouchEvent) => {
        // Only enable if we are at the very top of the page
        if (window.scrollY < 10) {
            touchStartRef.current = e.touches[0].clientY;
            isDraggingRef.current = true;
        }
    };

    const handleTouchMove = (e: TouchEvent) => {
        if (!isDraggingRef.current) return;

        const currentY = e.touches[0].clientY;
        const diff = currentY - touchStartRef.current;

        // If user scrolls down instead of pulling, or page is scrolled, cancel drag
        if (window.scrollY > 10 || diff < 0) {
            isDraggingRef.current = false;
            setPullDistance(0);
            currentPullYRef.current = 0;
            return;
        }

        if (diff > 0) {
            // Prevent native scrolling behavior (bounce/reload)
            if (e.cancelable) e.preventDefault();

            // Add resistance (logarithmic-ish feels best)
            const damped = Math.min(diff * 0.45, 140); 
            currentPullYRef.current = damped;
            setPullDistance(damped);
        }
    };

    const handleTouchEnd = async () => {
        if (!isDraggingRef.current) return;
        isDraggingRef.current = false;

        const triggerThreshold = 64;

        if (currentPullYRef.current > triggerThreshold) {
            // Snap to loading position
            setPullDistance(64);
            setIsRefreshing(true);

            // Haptic feedback if available
            if (typeof navigator !== 'undefined' && navigator.vibrate) {
                navigator.vibrate(20);
            }

            try {
                // Minimum delay for visual feel
                const startTime = Date.now();
                await loadPostsRef.current();
                const elapsed = Date.now() - startTime;
                if (elapsed < 800) {
                    await new Promise(r => setTimeout(r, 800 - elapsed));
                }
            } finally {
                setIsRefreshing(false);
                setPullDistance(0);
                currentPullYRef.current = 0;
            }
        } else {
            // Snap back
            setPullDistance(0);
            currentPullYRef.current = 0;
        }
    };

    // Passive: false is required to preventDefault inside touchmove
    document.addEventListener('touchstart', handleTouchStart, { passive: true });
    document.addEventListener('touchmove', handleTouchMove, { passive: false });
    document.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
        document.removeEventListener('touchstart', handleTouchStart);
        document.removeEventListener('touchmove', handleTouchMove);
        document.removeEventListener('touchend', handleTouchEnd);
    };
  }, []);

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, [loadPosts]);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    setPosts(prev => prev.filter(p => p.id !== postId));
    if (!postId.includes('-') && /^\d+$/.test(postId)) return;
    try {
        await SupabaseService.deletePost(postId);
    } catch (e: any) {
        console.error("Delete failed", e);
        alert(`Failed to delete. You might not be the owner.\n\n${getErrorMessage(e)}`);
        loadPosts();
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    const sql = `
-- 1. Tables & Columns (Idempotent Migration)
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table posts add column if not exists nickname text;
alter table posts add column if not exists content text;
alter table posts add column if not exists tags text[] default '{}';
alter table posts add column if not exists likes int default 0;
alter table posts add column if not exists avatar_seed text;
alter table posts add column if not exists user_id uuid;

create table if not exists comments (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table comments add column if not exists post_id uuid references posts(id) on delete cascade;
alter table comments add column if not exists user_id uuid;
-- FIX: Ensure nickname exists
alter table comments add column if not exists nickname text;
alter table comments add column if not exists avatar_seed text;
alter table comments add column if not exists content text;
alter table comments add column if not exists body text;
-- Legacy compatibility: make body nullable if we prefer content
alter table comments alter column body drop not null;

-- 2. Indexes & RLS
create index if not exists idx_posts_user_id on posts(user_id);
create index if not exists idx_comments_post_id on comments(post_id);

alter table posts enable row level security;
alter table comments enable row level security;

-- 3. Automatic User ID Trigger
create or replace function set_user_id()
returns trigger as $$
begin
  if auth.uid() is not null then
    new.user_id := auth.uid();
  elsif current_setting('request.headers', true)::json->>'x-shadow-user-id' is not null then
    new.user_id := (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid;
  end if;
  return new;
end;
$$ language plpgsql;

drop trigger if exists set_user_id_posts on posts;
create trigger set_user_id_posts before insert on posts for each row execute function set_user_id();

drop trigger if exists set_user_id_comments on comments;
create trigger set_user_id_comments before insert on comments for each row execute function set_user_id();

-- 4. Policies (Refresh)
drop policy if exists "Universal Read" on posts;
drop policy if exists "Universal Insert" on posts;
drop policy if exists "Universal Delete" on posts;
drop policy if exists "Universal Read Comments" on comments;
drop policy if exists "Universal Insert Comments" on comments;
drop policy if exists "Universal Delete Comments" on comments;

create policy "Universal Read" on posts for select using (true);
create policy "Universal Insert" on posts for insert with check (true);
create policy "Universal Delete" on posts for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);

create policy "Universal Read Comments" on comments for select using (true);
create policy "Universal Insert Comments" on comments for insert with check (true);
create policy "Universal Delete Comments" on comments for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
`;
    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
      setActiveFilter({ type: 'tag', value: rawTag });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUserClick = (nickname: string) => {
      setActiveFilter({ type: 'user', value: nickname });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const clearFilter = () => setActiveFilter(null);

  const filteredPosts = useMemo(() => {
      if (!activeFilter) return posts;
      if (activeFilter.type === 'tag') {
          return posts.filter(post => 
              post.tags.some(t => t.toLowerCase() === activeFilter.value.toLowerCase())
          );
      }
      if (activeFilter.type === 'user') {
          return posts.filter(post => post.author.nickname === activeFilter.value);
      }
      return posts;
  }, [posts, activeFilter]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => {
        if (post.tags && Array.isArray(post.tags)) {
            post.tags.forEach(tag => {
                if(tag) counts[tag] = (counts[tag] || 0) + 1;
            });
        }
    });
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    return sorted.slice(0, 10).map(t => '#' + t[0]);
  }, [posts]);

  const isOwner = (post: Post) => {
    if (!authUserId) return false;
    return post.author.userId === authUserId;
  };

  const statusColor = authUserId && !authUserId.includes('-') && authUserId.length > 30
      ? 'text-green-500' 
      : 'text-yellow-500';

  return (
    <div className="min-h-screen transition-colors duration-300 bg-[#FAFAFA] text-neutral-900 dark:bg-[#050505] dark:text-white">

      {/* Pull To Refresh Indicator */}
      <div 
        className="fixed left-1/2 -translate-x-1/2 z-50 transition-all duration-300 pointer-events-none"
        style={{ top: `${Math.max(20, pullDistance + 20)}px` }}
      >
        <div 
            className={`
                bg-white dark:bg-neutral-800 rounded-full p-2 shadow-lg border border-neutral-100 dark:border-neutral-700
                flex items-center justify-center transition-all
                ${pullDistance === 0 && !isRefreshing ? 'opacity-0 scale-75' : 'opacity-100 scale-100'}
            `}
        >
            <RefreshCw 
                size={20} 
                className={`
                    text-black dark:text-white 
                    ${isRefreshing ? 'animate-spin' : ''}
                `} 
                style={{ 
                    transform: isRefreshing ? 'none' : `rotate(${pullDistance * 2}deg)` 
                }}
            />
        </div>
      </div>

      {/* Sticky Header */}
      <header className="sticky top-0 z-30 w-full backdrop-blur-xl bg-white/80 dark:bg-black/80 border-b border-neutral-200 dark:border-white/10">
        <div className="max-w-2xl mx-auto px-4 h-16 flex items-center justify-between">
            <div 
                onClick={() => { clearFilter(); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
                className="flex items-center gap-2 cursor-pointer group"
            >
                <span className="font-bold text-xl tracking-tight">Echo</span>
            </div>

            <div className="flex items-center gap-3">
                <button 
                    onClick={() => setShowDebug(!showDebug)}
                    className={`p-2 rounded-full transition-colors ${showDebug ? 'bg-neutral-100 dark:bg-white/10 text-black dark:text-white' : 'text-neutral-400 hover:text-black dark:hover:text-white'}`}
                >
                    <Info size={20} />
                </button>
                <button 
                    onClick={toggleTheme} 
                    className="p-2 rounded-full text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-white/10 transition-colors"
                >
                    {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                </button>
            </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-2xl mx-auto px-4 py-8">

        {/* Error Banner */}
        {errorMsg && (
            <div className="mb-8 p-4 rounded-2xl border border-red-200 bg-red-50 text-red-800 dark:border-red-900/50 dark:bg-red-900/20 dark:text-red-200 shadow-sm animate-in slide-in-from-top-4">
                <div className="flex items-start gap-3">
                    <XCircle className="shrink-0 mt-0.5" size={20} />
                    <div className="space-y-2 w-full">
                        <h3 className="font-bold text-sm">Connection Error</h3>
                        <p className="text-xs opacity-90 font-mono break-all">{errorMsg}</p>
                        {/* Prompt for schema fix */}
                        {(errorMsg.includes("column") && errorMsg.includes("does not exist")) && (
                            <div className="mt-3 p-2 bg-white/50 dark:bg-black/20 rounded border border-red-200 dark:border-red-800/50 text-xs">
                                <strong>Tip:</strong> Your database tables are missing columns (likely <code>nickname</code>). Click the button below to copy the SQL repair script, then run it in your Supabase SQL Editor.
                            </div>
                        )}
                        <button 
                            onClick={copySQL}
                            className="mt-2 text-xs bg-white dark:bg-black px-3 py-1.5 rounded-lg border border-red-100 dark:border-red-900/30 font-medium flex items-center gap-2 w-fit hover:border-red-300 transition-colors"
                        >
                            {copied ? <Check size={12} className="text-green-500" /> : <Database size={12} />}
                            {copied ? 'SQL Copied' : 'Copy SQL Fix'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Debug / Status Panel */}
        {showDebug && (
            <div className="mb-8 p-6 rounded-[32px] bg-white dark:bg-[#0F0F0F] border border-neutral-200 dark:border-neutral-800 shadow-sm">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-lg">System Status</h3>
                    <div className={`flex items-center gap-2 text-xs font-bold px-3 py-1 rounded-full bg-neutral-100 dark:bg-neutral-800 ${statusColor}`}>
                        <div className="w-2 h-2 rounded-full bg-current animate-pulse" />
                        {authUserId && !authUserId.includes('-') && authUserId.length > 30 ? 'AUTHENTICATED' : 'SHADOW MODE'}
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-1">User ID</div>
                        <code className="text-xs font-mono bg-neutral-100 dark:bg-black px-2 py-1 rounded block overflow-hidden text-ellipsis">{authUserId || 'Loading...'}</code>
                    </div>
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-2">Actions</div>
                        <button 
                            onClick={copySQL}
                            className="text-xs flex items-center gap-2 px-4 py-2 bg-black text-white dark:bg-white dark:text-black rounded-full font-medium active:scale-95 transition-transform"
                        >
                            <Terminal size={14} />
                            {copied ? 'Copied to Clipboard' : 'Copy Database Setup SQL'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Input Area (Hidden if filtering) */}
        {!activeFilter && !isAuthLoading && (
            <>
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                {/* Trending Scroll - Only show if there are actual tags */}
                {trendingTopics.length > 0 && (
                    <div className="flex items-center gap-2 overflow-x-auto pb-4 pt-2 no-scrollbar mask-gradient">
                        <div className="flex items-center gap-2 pr-4">
                            <Sparkles size={14} className="text-neutral-400" />
                            <span className="text-xs font-bold text-neutral-400 uppercase tracking-wider whitespace-nowrap">Trending:</span>
                        </div>
                        {trendingTopics.map((topic, i) => (
                            <button
                                key={i}
                                onClick={() => handleTagClick(topic)}
                                className="px-3 py-1.5 rounded-full bg-white border border-neutral-200 text-xs font-medium text-neutral-600 hover:border-black hover:text-black whitespace-nowrap transition-all
                                        dark:bg-[#111] dark:border-neutral-800 dark:text-neutral-400 dark:hover:border-white dark:hover:text-white"
                            >
                                {topic}
                            </button>
                        ))}
                    </div>
                )}
            </>
        )}

        {/* Active Filter Banner */}
        {activeFilter && (
            <div className="mb-6 flex items-center justify-between p-1 pl-1 pr-4 rounded-full bg-black text-white dark:bg-white dark:text-black animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-full bg-white/20 dark:bg-black/10">
                        {activeFilter.type === 'tag' ? <Hash size={20} /> : <AtSign size={20} />}
                    </div>
                    <div>
                        <div className="text-[10px] uppercase font-bold opacity-60 tracking-wider">
                            {activeFilter.type === 'tag' ? 'Viewing Tag' : 'Viewing User'}
                        </div>
                        <h3 className="font-bold text-sm">
                            {activeFilter.type === 'tag' ? `#${activeFilter.value}` : activeFilter.value}
                        </h3>
                    </div>
                </div>
                <button onClick={clearFilter} className="p-2 rounded-full hover:bg-white/20 dark:hover:bg-black/10 transition-colors">
                    <X size={18} />
                </button>
            </div>
        )}

        {/* Feed */}
        <div 
            className="space-y-4 min-h-[50vh] transition-transform duration-100 ease-out"
            style={{ 
                // subtle push down effect on the feed for extra visual feedback, though typically only the indicator moves
                transform: `translateY(${pullDistance * 0.3}px)` 
            }}
        >
            {(isLoading || isAuthLoading) && posts.length === 0 ? (
                 <div className="flex flex-col items-center justify-center py-20 opacity-50 space-y-4">
                    <div className="w-8 h-8 border-2 border-current border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-sm font-medium">Loading feed...</p>
                 </div>
            ) : filteredPosts.length === 0 ? (
                <div className="text-center py-20 opacity-60">
                    <div className="text-4xl mb-4 grayscale flex justify-center">
                        {activeFilter ? (activeFilter.type === 'tag' ? '🔭' : '👤') : '🎙️'}
                    </div>
                    <h2 className="text-lg font-medium mb-1">
                        {activeFilter ? 'No signals found' : 'Echo is quiet'}
                    </h2>
                    <p className="text-sm text-neutral-500">
                        {activeFilter 
                            ? (activeFilter.type === 'tag' ? `Be the first to tag #${activeFilter.value}` : `No posts from ${activeFilter.value} yet`)
                            : 'Start the conversation'}
                    </p>
                    {activeFilter && (
                        <button onClick={clearFilter} className="mt-4 text-sm font-bold underline hover:text-black dark:hover:text-white">
                            View All Posts
                        </button>
                    )}
                </div>
            ) : (
                filteredPosts.map(post => (
                    <PostCard 
                        key={post.id} 
                        post={post} 
                        isUser={isOwner(post)} 
                        onDelete={handleDeletePost}
                        onTagClick={handleTagClick}
                        onUserClick={handleUserClick}
                    />
                ))
            )}
        </div>

        {/* Footer */}
        <footer className="mt-20 py-8 border-t border-neutral-100 dark:border-white/5 flex flex-col items-center gap-4 text-neutral-400">
            <div className="flex items-center gap-2 text-xs font-medium">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                Live Connection
            </div>
            <p className="text-[10px] uppercase tracking-widest opacity-50">
                Echo • Decentralized Feed
            </p>
        </footer>

      </main>
    </div>
  );
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, Check, Hash, X, Info, Sparkles, AtSign, Loader2, ArrowDown } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import * as SupabaseService from './services/supabaseClient';

type FilterState = { type: 'tag' | 'user'; value: string } | null;

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  const [activeFilter, setActiveFilter] = useState<FilterState>(null);

  const [showDebug, setShowDebug] = useState(false);

  // Pull-to-Refresh State
  const [pullDistance, setPullDistance] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const touchStartRef = useRef(0);
  const isDraggingRef = useRef(false);
  const currentPullYRef = useRef(0);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    if (typeof e === 'object') return JSON.stringify(e);
    return String(e);
  };

  const loadPosts = useCallback(async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      if (posts.length === 0) {
        const msg = getErrorMessage(e);
        setErrorMsg(msg);
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  }, [posts.length]);

  // Pull to Refresh Logic
  const loadPostsRef = useRef(loadPosts);
  useEffect(() => { loadPostsRef.current = loadPosts; }, [loadPosts]);

  useEffect(() => {
    const handleTouchStart = (e: TouchEvent) => {
        // Only start if we are at the top and not already refreshing
        if (window.scrollY <= 0 && !isRefreshing) {
            touchStartRef.current = e.touches[0].clientY;
            isDraggingRef.current = true;
        }
    };

    const handleTouchMove = (e: TouchEvent) => {
        if (!isDraggingRef.current || isRefreshing) return;

        const currentY = e.touches[0].clientY;
        const diff = currentY - touchStartRef.current;

        // If dragging up or page is scrolled, cancel
        if (diff < 0 || window.scrollY > 0) {
            isDraggingRef.current = false;
            setPullDistance(0);
            return;
        }

        if (diff > 0) {
            if (e.cancelable) e.preventDefault();

            // Material Design 3 style logarithmic damping
            // Allows the pull to feel "heavy" as you pull further down
            const limit = 180; // Maximum pixels the content can move
            const dampFactor = 0.5;
            // Damping formula: result = limit * (1 - e^(-diff / (limit * 2))) ? 
            // Simplified Logarithmic:
            const damped = Math.min(Math.pow(diff, 0.8), limit);

            currentPullYRef.current = damped;
            setPullDistance(damped);
        }
    };

    const handleTouchEnd = async () => {
        if (!isDraggingRef.current || isRefreshing) return;
        isDraggingRef.current = false;

        const triggerThreshold = 80; // Distance needed to trigger refresh

        if (currentPullYRef.current > triggerThreshold) {
            setIsRefreshing(true);
            setPullDistance(triggerThreshold); // Snap to threshold

            // Haptic
            if (typeof navigator !== 'undefined' && navigator.vibrate) {
                navigator.vibrate(10);
            }

            try {
                const startTime = Date.now();
                await loadPostsRef.current();
                const elapsed = Date.now() - startTime;
                // Ensure spinner shows for at least 600ms for visual feedback
                if (elapsed < 600) {
                    await new Promise(r => setTimeout(r, 600 - elapsed));
                }
            } finally {
                setIsRefreshing(false);
                setPullDistance(0);
                currentPullYRef.current = 0;
            }
        } else {
            // Snap back without refreshing
            setPullDistance(0);
            currentPullYRef.current = 0;
        }
    };

    // Use active listeners to preventDefault properly
    document.addEventListener('touchstart', handleTouchStart, { passive: true });
    document.addEventListener('touchmove', handleTouchMove, { passive: false });
    document.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
        document.removeEventListener('touchstart', handleTouchStart);
        document.removeEventListener('touchmove', handleTouchMove);
        document.removeEventListener('touchend', handleTouchEnd);
    };
  }, [isRefreshing]);

  useEffect(() => {
    const subscription = SupabaseService.subscribeToPosts((payload) => {
      if (payload.eventType === 'INSERT' || payload.eventType === 'DELETE') {
        loadPosts();
      }
    });
    return () => { subscription?.unsubscribe(); };
  }, [loadPosts]);

  const handleUserPost = async (nickname: string, content: string, tags: string[]) => {
    if (!authUserId) return;
    setCurrentUserNickname(nickname);

    const tempId = Date.now().toString(); 
    const tempPost: Post = {
        id: tempId,
        author: { 
            nickname, 
            avatarSeed: nickname, 
            isAi: false,
            userId: authUserId
        },
        content,
        tags,
        timestamp: Date.now(),
        likes: 0,
        comments: []
    };

    setPosts(prev => [tempPost, ...prev]);

    try {
        const realPost = await SupabaseService.createPost(nickname, content, tags);
        if (realPost) {
            setPosts(prev => prev.map(p => p.id === tempId ? realPost : p));
        }
    } catch (e: any) {
        console.error("Post failed", e);
        setPosts(prev => prev.filter(p => p.id !== tempId)); 
        alert(`Failed to post.\n\n${getErrorMessage(e)}`);
    }
  };

  const handleDeletePost = async (postId: string) => {
    setPosts(prev => prev.filter(p => p.id !== postId));
    if (!postId.includes('-') && /^\d+$/.test(postId)) return;
    try {
        await SupabaseService.deletePost(postId);
    } catch (e: any) {
        console.error("Delete failed", e);
        alert(`Failed to delete. You might not be the owner.\n\n${getErrorMessage(e)}`);
        loadPosts();
    }
  };

  const toggleTheme = () => setTheme(prev => prev === 'dark' ? 'light' : 'dark');

  const copySQL = () => {
    const sql = `
-- 1. Tables & Columns (Idempotent Migration)
create table if not exists posts (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table posts add column if not exists nickname text;
alter table posts add column if not exists content text;
alter table posts add column if not exists tags text[] default '{}';
alter table posts add column if not exists likes int default 0;
alter table posts add column if not exists avatar_seed text;
alter table posts add column if not exists user_id uuid;

create table if not exists comments (
  id uuid default gen_random_uuid() primary key,
  created_at timestamptz default now()
);
alter table comments add column if not exists post_id uuid references posts(id) on delete cascade;
alter table comments add column if not exists user_id uuid;
-- FIX: Ensure nickname exists
alter table comments add column if not exists nickname text;
alter table comments add column if not exists avatar_seed text;
alter table comments add column if not exists content text;
alter table comments add column if not exists body text;
-- Legacy compatibility: make body nullable if we prefer content
alter table comments alter column body drop not null;

-- 2. Indexes & RLS
create index if not exists idx_posts_user_id on posts(user_id);
create index if not exists idx_comments_post_id on comments(post_id);

alter table posts enable row level security;
alter table comments enable row level security;

-- 3. Automatic User ID Trigger
create or replace function set_user_id()
returns trigger as $$
begin
  if auth.uid() is not null then
    new.user_id := auth.uid();
  elsif current_setting('request.headers', true)::json->>'x-shadow-user-id' is not null then
    new.user_id := (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid;
  end if;
  return new;
end;
$$ language plpgsql;

drop trigger if exists set_user_id_posts on posts;
create trigger set_user_id_posts before insert on posts for each row execute function set_user_id();

drop trigger if exists set_user_id_comments on comments;
create trigger set_user_id_comments before insert on comments for each row execute function set_user_id();

-- 4. Policies (Refresh)
drop policy if exists "Universal Read" on posts;
drop policy if exists "Universal Insert" on posts;
drop policy if exists "Universal Delete" on posts;
drop policy if exists "Universal Read Comments" on comments;
drop policy if exists "Universal Insert Comments" on comments;
drop policy if exists "Universal Delete Comments" on comments;

create policy "Universal Read" on posts for select using (true);
create policy "Universal Insert" on posts for insert with check (true);
create policy "Universal Delete" on posts for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);

create policy "Universal Read Comments" on comments for select using (true);
create policy "Universal Insert Comments" on comments for insert with check (true);
create policy "Universal Delete Comments" on comments for delete using (
  (auth.uid() IS NOT NULL AND auth.uid() = user_id) OR
  (auth.uid() IS NULL AND (current_setting('request.headers', true)::json->>'x-shadow-user-id')::uuid = user_id)
);
`;
    navigator.clipboard.writeText(sql);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleTagClick = (tag: string) => {
      const rawTag = tag.replace(/^#/, '');
      setActiveFilter({ type: 'tag', value: rawTag });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const handleUserClick = (nickname: string) => {
      setActiveFilter({ type: 'user', value: nickname });
      window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const clearFilter = () => setActiveFilter(null);

  const filteredPosts = useMemo(() => {
      if (!activeFilter) return posts;
      if (activeFilter.type === 'tag') {
          return posts.filter(post => 
              post.tags.some(t => t.toLowerCase() === activeFilter.value.toLowerCase())
          );
      }
      if (activeFilter.type === 'user') {
          return posts.filter(post => post.author.nickname === activeFilter.value);
      }
      return posts;
  }, [posts, activeFilter]);

  const trendingTopics = useMemo(() => {
    const counts: Record<string, number> = {};
    posts.forEach(post => {
        if (post.tags && Array.isArray(post.tags)) {
            post.tags.forEach(tag => {
                if(tag) counts[tag] = (counts[tag] || 0) + 1;
            });
        }
    });
    const sorted = Object.entries(counts).sort((a, b) => b[1] - a[1]);
    return sorted.slice(0, 10).map(t => '#' + t[0]);
  }, [posts]);

  const isOwner = (post: Post) => {
    if (!authUserId) return false;
    return post.author.userId === authUserId;
  };

  const statusColor = authUserId && !authUserId.includes('-') && authUserId.length > 30
      ? 'text-green-500' 
      : 'text-yellow-500';

  return (
    <div className="min-h-screen transition-colors duration-300 bg-[#FAFAFA] text-neutral-900 dark:bg-[#050505] dark:text-white overflow-hidden">

      {/* Sticky Header */}
      <header className="fixed top-0 z-50 w-full backdrop-blur-xl bg-white/80 dark:bg-black/80 border-b border-neutral-200 dark:border-white/10">
        <div className="max-w-2xl mx-auto px-4 h-16 flex items-center justify-between">
            <div 
                onClick={() => { clearFilter(); window.scrollTo({ top: 0, behavior: 'smooth' }); }}
                className="flex items-center gap-2 cursor-pointer group"
            >
                <span className="font-bold text-xl tracking-tight">Echo</span>
            </div>

            <div className="flex items-center gap-3">
                <button 
                    onClick={() => setShowDebug(!showDebug)}
                    className={`p-2 rounded-full transition-colors ${showDebug ? 'bg-neutral-100 dark:bg-white/10 text-black dark:text-white' : 'text-neutral-400 hover:text-black dark:hover:text-white'}`}
                >
                    <Info size={20} />
                </button>
                <button 
                    onClick={toggleTheme} 
                    className="p-2 rounded-full text-neutral-400 hover:text-black dark:hover:text-white hover:bg-neutral-100 dark:hover:bg-white/10 transition-colors"
                >
                    {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
                </button>
            </div>
        </div>
      </header>

      {/* Pull To Refresh Indicator - M3 Style */}
      <div 
        className="fixed left-0 right-0 z-40 flex justify-center pointer-events-none"
        style={{ 
            // Positioned relatively to the pull distance.
            // Starts hidden above (-60px), moves down as pulled
            top: `${Math.min(pullDistance, 80) + 64 + 10}px`, // 64 (header) + 10 (spacing)
            opacity: pullDistance > 0 || isRefreshing ? 1 : 0,
            transition: isRefreshing ? 'top 0.3s ease' : 'none' // Smooth snap when refreshing, instant when dragging
        }}
      >
        <div 
            className={`
                bg-white dark:bg-[#1E1E1E] rounded-full p-2.5 shadow-md border border-neutral-100 dark:border-neutral-700
                flex items-center justify-center transform transition-transform duration-200
                ${pullDistance > 0 || isRefreshing ? 'scale-100' : 'scale-50'}
            `}
        >
            {isRefreshing ? (
                <Loader2 size={20} className="text-blue-600 dark:text-blue-400 animate-spin" />
            ) : (
                <ArrowDown 
                    size={20} 
                    className="text-blue-600 dark:text-blue-400"
                    style={{ 
                        transform: `rotate(${Math.min(pullDistance * 2, 180)}deg)`,
                        opacity: Math.min(pullDistance / 40, 1)
                    }}
                />
            )}
        </div>
      </div>

      {/* Main Content Wrapper - Moves down on pull */}
      <main 
        className="max-w-2xl mx-auto px-4 py-8 pt-24 min-h-screen relative"
        style={{
             transform: `translateY(${pullDistance}px)`,
             transition: isRefreshing ? 'transform 0.3s cubic-bezier(0.2, 0.0, 0.2, 1)' : 'none' // Bounce back animation
        }}
      >

        {/* Error Banner */}
        {errorMsg && (
            <div className="mb-8 p-4 rounded-2xl border border-red-200 bg-red-50 text-red-800 dark:border-red-900/50 dark:bg-red-900/20 dark:text-red-200 shadow-sm animate-in slide-in-from-top-4">
                <div className="flex items-start gap-3">
                    <XCircle className="shrink-0 mt-0.5" size={20} />
                    <div className="space-y-2 w-full">
                        <h3 className="font-bold text-sm">Connection Error</h3>
                        <p className="text-xs opacity-90 font-mono break-all">{errorMsg}</p>
                        {/* Prompt for schema fix */}
                        {(errorMsg.includes("column") && errorMsg.includes("does not exist")) && (
                            <div className="mt-3 p-2 bg-white/50 dark:bg-black/20 rounded border border-red-200 dark:border-red-800/50 text-xs">
                                <strong>Tip:</strong> Your database tables are missing columns (likely <code>nickname</code>). Click the button below to copy the SQL repair script, then run it in your Supabase SQL Editor.
                            </div>
                        )}
                        <button 
                            onClick={copySQL}
                            className="mt-2 text-xs bg-white dark:bg-black px-3 py-1.5 rounded-lg border border-red-100 dark:border-red-900/30 font-medium flex items-center gap-2 w-fit hover:border-red-300 transition-colors"
                        >
                            {copied ? <Check size={12} className="text-green-500" /> : <Database size={12} />}
                            {copied ? 'SQL Copied' : 'Copy SQL Fix'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Debug / Status Panel */}
        {showDebug && (
            <div className="mb-8 p-6 rounded-[32px] bg-white dark:bg-[#0F0F0F] border border-neutral-200 dark:border-neutral-800 shadow-sm">
                <div className="flex items-center justify-between mb-4">
                    <h3 className="font-bold text-lg">System Status</h3>
                    <div className={`flex items-center gap-2 text-xs font-bold px-3 py-1 rounded-full bg-neutral-100 dark:bg-neutral-800 ${statusColor}`}>
                        <div className="w-2 h-2 rounded-full bg-current animate-pulse" />
                        {authUserId && !authUserId.includes('-') && authUserId.length > 30 ? 'AUTHENTICATED' : 'SHADOW MODE'}
                    </div>
                </div>
                <div className="space-y-4">
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-1">User ID</div>
                        <code className="text-xs font-mono bg-neutral-100 dark:bg-black px-2 py-1 rounded block overflow-hidden text-ellipsis">{authUserId || 'Loading...'}</code>
                    </div>
                    <div>
                        <div className="text-xs text-neutral-500 uppercase font-bold tracking-wider mb-2">Actions</div>
                        <button 
                            onClick={copySQL}
                            className="text-xs flex items-center gap-2 px-4 py-2 bg-black text-white dark:bg-white dark:text-black rounded-full font-medium active:scale-95 transition-transform"
                        >
                            <Terminal size={14} />
                            {copied ? 'Copied to Clipboard' : 'Copy Database Setup SQL'}
                        </button>
                    </div>
                </div>
            </div>
        )}

        {/* Input Area (Hidden if filtering) */}
        {!activeFilter && !isAuthLoading && (
            <>
                <CreatePost onPost={handleUserPost} defaultNickname={currentUserNickname} />

                {/* Trending Scroll - Only show if there are actual tags */}
                {trendingTopics.length > 0 && (
                    <div className="flex items-center gap-2 overflow-x-auto pb-4 pt-2 no-scrollbar mask-gradient">
                        <div className="flex items-center gap-2 pr-4">
                            <Sparkles size={14} className="text-neutral-400" />
                            <span className="text-xs font-bold text-neutral-400 uppercase tracking-wider whitespace-nowrap">Trending:</span>
                        </div>
                        {trendingTopics.map((topic, i) => (
                            <button
                                key={i}
                                onClick={() => handleTagClick(topic)}
                                className="px-3 py-1.5 rounded-full bg-white border border-neutral-200 text-xs font-medium text-neutral-600 hover:border-black hover:text-black whitespace-nowrap transition-all
                                        dark:bg-[#111] dark:border-neutral-800 dark:text-neutral-400 dark:hover:border-white dark:hover:text-white"
                            >
                                {topic}
                            </button>
                        ))}
                    </div>
                )}
            </>
        )}

        {/* Active Filter Banner */}
        {activeFilter && (
            <div className="mb-6 flex items-center justify-between p-1 pl-1 pr-4 rounded-full bg-black text-white dark:bg-white dark:text-black animate-in fade-in slide-in-from-top-4">
                <div className="flex items-center gap-3">
                    <div className="p-3 rounded-full bg-white/20 dark:bg-black/10">
                        {activeFilter.type === 'tag' ? <Hash size={20} /> : <AtSign size={20} />}
                    </div>
                    <div>
                        <div className="text-[10px] uppercase font-bold opacity-60 tracking-wider">
                            {activeFilter.type === 'tag' ? 'Viewing Tag' : 'Viewing User'}
                        </div>
                        <h3 className="font-bold text-sm">
                            {activeFilter.type === 'tag' ? `#${activeFilter.value}` : activeFilter.value}
                        </h3>
                    </div>
                </div>
                <button onClick={clearFilter} className="p-2 rounded-full hover:bg-white/20 dark:hover:bg-black/10 transition-colors">
                    <X size={18} />
                </button>
            </div>
        )}

        {/* Feed */}
        <div className="space-y-4 min-h-[50vh]">
            {(isLoading || isAuthLoading) && posts.length === 0 ? (
                 <div className="flex flex-col items-center justify-center py-20 opacity-50 space-y-4">
                    <div className="w-8 h-8 border-2 border-current border-t-transparent rounded-full animate-spin"></div>
                    <p className="text-sm font-medium">Loading feed...</p>
                 </div>
            ) : filteredPosts.length === 0 ? (
                <div className="text-center py-20 opacity-60">
                    <div className="text-4xl mb-4 grayscale flex justify-center">
                        {activeFilter ? (activeFilter.type === 'tag' ? '🔭' : '👤') : '🎙️'}
                    </div>
                    <h2 className="text-lg font-medium mb-1">
                        {activeFilter ? 'No signals found' : 'Echo is quiet'}
                    </h2>
                    <p className="text-sm text-neutral-500">
                        {activeFilter 
                            ? (activeFilter.type === 'tag' ? `Be the first to tag #${activeFilter.value}` : `No posts from ${activeFilter.value} yet`)
                            : 'Start the conversation'}
                    </p>
                    {activeFilter && (
                        <button onClick={clearFilter} className="mt-4 text-sm font-bold underline hover:text-black dark:hover:text-white">
                            View All Posts
                        </button>
                    )}
                </div>
            ) : (
                filteredPosts.map(post => (
                    <PostCard 
                        key={post.id} 
                        post={post} 
                        isUser={isOwner(post)} 
                        onDelete={handleDeletePost}
                        onTagClick={handleTagClick}
                        onUserClick={handleUserClick}
                    />
                ))
            )}
        </div>

        {/* Footer */}
        <footer className="mt-20 py-8 border-t border-neutral-100 dark:border-white/5 flex flex-col items-center gap-4 text-neutral-400">
            <div className="flex items-center gap-2 text-xs font-medium">
                <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
                Live Connection
            </div>
            <p className="text-[10px] uppercase tracking-widest opacity-50">
                Echo • Decentralized Feed
            </p>
        </footer>

      </main>
    </div>
  );
}

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, Check, Hash, X, Info, Sparkles, AtSign, Loader2, ArrowDown } from 'lucide-react';
import { CreatePost } from './components/CreatePost';
import { PostCard } from './components/PostCard';
import { Post } from './types';
import * as SupabaseService from './services/supabaseClient';

type FilterState = { type: 'tag' | 'user'; value: string } | null;

export default function App() {
  const [posts, setPosts] = useState<Post[]>([]);

  const [currentUserNickname, setCurrentUserNickname] = useState<string>(() => {
    if (typeof window !== 'undefined') {
        return localStorage.getItem('echo_nickname') || 'Guest';
    }
    return 'Guest';
  });

  const [authUserId, setAuthUserId] = useState<string | null>(null);
  const [errorMsg, setErrorMsg] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isAuthLoading, setIsAuthLoading] = useState(true);
  const [copied, setCopied] = useState(false);

  const [activeFilter, setActiveFilter] = useState<FilterState>(null);

  const [showDebug, setShowDebug] = useState(false);

  // Pull-to-Refresh State
  const [pullDistance, setPullDistance] = useState(0);
  const [isRefreshing, setIsRefreshing] = useState(false);
  const touchStartRef = useRef(0);
  const isDraggingRef = useRef(false);
  const currentPullYRef = useRef(0);

  const [theme, setTheme] = useState<'light' | 'dark'>(() => {
    if (typeof window !== 'undefined') {
      const saved = localStorage.getItem('echo_theme');
      return saved === 'light' || saved === 'dark' ? saved : 'light';
    }
    return 'light';
  });

  useEffect(() => {
    const root = window.document.documentElement;
    if (theme === 'dark') root.classList.add('dark');
    else root.classList.remove('dark');
    localStorage.setItem('echo_theme', theme);
  }, [theme]);

  useEffect(() => {
    localStorage.setItem('echo_nickname', currentUserNickname);
  }, [currentUserNickname]);

  // Init Auth and Load Data
  useEffect(() => {
    const init = async () => {
        try {
            setIsAuthLoading(true);
            const uid = await SupabaseService.initializeAuth();
            setAuthUserId(uid);
            await loadPosts();
        } catch (e: any) {
            console.error("Critical Init Failure", e);
            setErrorMsg(getErrorMessage(e));
        } finally {
            setIsAuthLoading(false);
            setIsLoading(false);
        }
    };
    init();
  }, []);

  const getErrorMessage = (e: any) => {
    if (!e) return "Unknown error";
    if (e.code && e.message) return `Error ${e.code}: ${e.message}`;
    if (e.message) return e.message;
    if (typeof e === 'object') return JSON.stringify(e);
    return String(e);
  };

  const loadPosts = useCallback(async () => {
    try {
      const remotePosts = await SupabaseService.fetchPosts();
      setPosts(remotePosts);
    } catch (e: any) {
      console.error("Failed to load posts", e);
      if (posts.length === 0) {
        const msg = getErrorMessage(e);
        setErrorMsg(msg);
        if (msg.includes("column") && msg.includes("does not exist")) {
            setShowDebug(true);
        }
      }
    }
  }, [posts.length]);

  // Pull to Refresh Logic
  const loadPostsRef = useRef(loadPosts);
  useEffect(() => { loadPostsRef.current = loadPosts; }, [loadPosts]);

  useEffect(() => {
    const handleTouchStart = (e: TouchEvent) => {
        // Only start if we are at the top and not already refreshing
        if (window.scrollY <= 0 && !isRefreshing) {
            touchStartRef.current = e.touches[0].clientY;
            isDraggingRef.current = true;
        }
    };

    const handleTouchMove = (e: TouchEvent) => {
        if (!isDraggingRef.current || isRefreshing) return;

        const currentY = e.touches[0].clientY;
        const diff = currentY - touchStartRef.current;

        // If dragging up or page is scrolled, cancel
        if (diff < 0 || window.scrollY > 0) {
            isDraggingRef.current = false;
            setPullDistance(0);
            return;
        }

        if (diff > 0) {
            if (e.cancelable) e.preventDefault();

            // Material Design 3 style logarithmic damping
            // Allows the pull to feel "heavy" as you pull further down
            const limit = 180; // Maximum pixels the content can move
            const dampFactor = 0.5;
            // Damping formula: result = limit * (1 - e^(-diff / (limit * 2))) ? 
            // Simplified Logarithmic:
            const damped = Math.min(Math.pow(diff, 0.8), limit);

            currentPullYRef.current = damped;
            setPullDistance(damped);
        }
    };

    const handleTouchEnd = async () => {
        if (!isDraggingRef.current || isRefreshing) return;
        isDraggingRef.current = false;

        const triggerThreshold = 80; // Distance needed to trigger refresh

        if (currentPullYRef.current > triggerThreshold) {
            setIsRefreshing(true);
            setPullDistance(triggerThreshold); // Snap to threshold

            // Haptic
            if (typeof navigator !== 'undefined' && navigator.vibrate) {
                navigator.vibrate(10);
            }

            try {
                const startTime = Date.now();
                await loadPostsRef.current();
                const elapsed = Date.now() - startTime;
                // Ensure spinner shows for at least 600ms for visual feedback
                if (elapsed < 600) {
                    await new Promise(r => setTimeout(r, 600 - elapsed));
                }
            } finally {
                setIsRefreshing(false);
                setPullDistance(0);
                currentPullYRef.current = 0;
            }
        } else {
            // Snap back without refreshing
            setPullDistance(0);
            currentPullYRef.current = 0;
        }
    };

    // Use active listeners to preventDefault properly
    document.addEventListener('touchstart', handleTouchStart, { passive: true });
    document.addEventListener('touchmove', handleTouchMove, { passive: false });
    document.addEventListener('touchend', handleTouchEnd, { passive: true });

    return () => {
        document.removeEventListener('touchstart', handleTouchStart);
        document.removeEventListener('touchmove', handleTouchMove);
        document.removeEventListener('touchend', handleTouchEnd);
    };
  }, [isRefreshing]);

