  if (session?.user) {
      return session.user.id;
  }
  return SHADOW_USER_ID;
};

// --- DATA MAPPING ---

const mapRowToComment = (row: any): Comment => ({
  id: row.id,
  author: {
    nickname: row.nickname || 'Anonymous', // Fallback if column missing (though query will fail first)
    avatarSeed: row.avatar_seed || row.nickname || 'default',
    isAi: false, 
    userId: row.user_id
  },
  content: row.content || row.body || '', // Handle legacy 'body' column
  timestamp: new Date(row.created_at).getTime(),
  likes: 0 
});

const mapRowToPost = (row: any): Post => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false,
    userId: row.user_id 
  },
  content: row.content,
  tags: row.tags || [],
  timestamp: new Date(row.created_at).getTime(),
  likes: row.likes,
  comments: (row.comments || []).map(mapRowToComment).sort((a: Comment, b: Comment) => a.timestamp - b.timestamp)
});

// --- API METHODS ---

export const fetchPosts = async (): Promise<Post[]> => {
  try {
    // We select both content and body to be safe with legacy schemas
    // Note: If 'nickname' is missing in DB, this query will fail.
    // The App.tsx error handler catches this and prompts the SQL fix.
    const { data, error } = await supabase
      .from('posts')
      .select(`
        *,
        comments (
          id,
          content,
          body,
          nickname,
          avatar_seed,
          user_id,
          created_at
        )
      `)
      .order('created_at', { ascending: false })
      .limit(MAX_POSTS_LIMIT);

    if (error) throw error;
    return (data || []).map(mapRowToPost);
  } catch (error) {
    console.error("[Echo] Fetch Posts Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  // Validation
  if (!content || content.trim().length === 0) throw new Error("Content cannot be empty");
  if (content.length > 2000) throw new Error("Content exceeds 2000 characters");

  try {
    // Note: We DO NOT send user_id. We rely on DB Triggers or Policies to assign it.
    const { data, error } = await supabase
      .from('posts')
      .insert([{
        nickname,
        content,
        tags,
        avatar_seed: nickname,
        likes: 0
        // user_id removed -> handled by DB Trigger
      }])
      .select()
      .single();

    if (error) throw error;

    cleanUpOldPosts(supabase);
    // Return post with empty comments array initially
    return mapRowToPost({ ...data, comments: [] });
  } catch (error) {
    console.error("[Echo] Create Post Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const deletePost = async (id: string): Promise<void> => {
  if (!validateUUID(id)) throw new Error("Invalid Post ID (UUID required)");

  console.log(`[Echo] Requesting delete for post ${id}...`);

  try {
    const { error, count } = await supabase
      .from('posts')
      .delete({ count: 'exact' })
      .eq('id', id);

    if (error) throw error;

    if (count === 0) {
        throw new Error("Could not delete post. Permission denied or post not found.");
    }
  } catch (error) {
    console.error("[Echo] Delete Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

// --- COMMENTS ---

export const createComment = async (postId: string, content: string, nickname: string): Promise<Comment> => {
  // Validation
  if (!validateUUID(postId)) throw new Error("Invalid Post ID");
  if (!content || content.trim().length === 0) throw new Error("Comment cannot be empty");
  if (content.length > 2000) throw new Error("Comment exceeds 2000 characters");

  try {
    // Note: We DO NOT send user_id. We rely on DB Triggers or Policies to assign it.
    // We send BOTH content and body to satisfy potential DB constraints (body not null)
    const { data, error } = await supabase
      .from('comments')
      .insert([{
        post_id: postId,
        content: content,
        body: content, // Legacy column support
        nickname,
        avatar_seed: nickname
        // user_id removed -> handled by DB Trigger
      }])
      .select()
      .single();

    if (error) throw error;

    return mapRowToComment(data);
  } catch (error) {
    console.error("[Echo] Create Comment Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const deleteComment = async (commentId: string): Promise<void> => {
  if (!validateUUID(commentId)) throw new Error("Invalid Comment ID");

  try {
    const { error, count } = await supabase
      .from('comments')
      .delete({ count: 'exact' })
      .eq('id', commentId);

    if (error) throw error;

    if (count === 0) {
      throw new Error("Could not delete comment. Permission denied or comment not found.");
    }
  } catch (error) {
    console.error("[Echo] Delete Comment Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

const cleanUpOldPosts = async (client: SupabaseClient) => {
  try {
    const { count } = await client.from('posts').select('*', { count: 'exact', head: true });

    if (count !== null && count > MAX_POSTS_LIMIT) {
      const excess = count - MAX_POSTS_LIMIT;
      const { data: oldPosts } = await client
        .from('posts')
        .select('id')
        .order('created_at', { ascending: true })
        .limit(excess + 5); 

      if (oldPosts && oldPosts.length > 0) {
        const ids = oldPosts.map(p => p.id);
        await client.from('posts').delete().in('id', ids);
      }
    }
  } catch (e) {
    // Ignore cleanup errors
  }
};

export const toggleLike = async (postId: string, increment: boolean) => {
  if (!validateUUID(postId)) return;
  try {
    const { data } = await supabase.from('posts').select('likes').eq('id', postId).single();
    if (data) {
      const newLikes = Math.max(0, data.likes + (increment ? 1 : -1));
      await supabase.from('posts').update({ likes: newLikes }).eq('id', postId);
    }
  } catch (e) {
    console.error("[Echo] Like failed:", formatError(e));
  }
};

export const subscribeToPosts = (callback: (payload: any) => void) => {
  return supabase
    .channel('public:posts_and_comments')
    .on('postgres_changes', { event: '*', schema: 'public', table: 'posts' }, callback)
    .on('postgres_changes', { event: '*', schema: 'public', table: 'comments' }, callback)
    .subscribe();
};

import React, { useState, useEffect, useRef, useMemo, useCallback } from 'react';
import { Sun, Moon, Database, XCircle, Terminal, Check, Hash, X, Info, Sparkles, AtSign, Loader2, ArrowDown } from 'lucide-react';
