/**
 * Deletes a post safely using the authenticated session.
 * 
 * Flow:
 * 1. Check for active session.
 * 2. If no session, abort (Security requirement).
 * 3. Call delete with count='exact' to verify RLS success.
 * 4. If token expired (401), attempt refresh and retry once.
 */
export const deletePost = async (id: string): Promise<void> => {
  if (!id) throw new Error("Invalid Post ID");
  console.log(`[Echo] Requesting delete for post ${id}...`);

  // 1. Authenticate Request
  let { data: { session }, error: sessionError } = await supabase.auth.getSession();

  // If no session found, try one explicit refresh just in case
  if (sessionError || !session) {
      const { data: refreshData, error: refreshError } = await supabase.auth.refreshSession();
      if (refreshError || !refreshData.session) {
         throw new Error("Authentication required. Please sign in to delete posts.");
      }
      session = refreshData.session;
  }

  // 2. Perform Delete with Retry Loop
  let attempts = 0;
  const maxAttempts = 2;

  while (attempts < maxAttempts) {
    attempts++;

    // Supabase client automatically attaches Authorization: Bearer <token>
    const { error, count } = await supabase
      .from('posts')
      .delete({ count: 'exact' })
      .eq('id', id);

    if (!error) {
      // If count is 0, it means the row exists but RLS hid it (permission denied),
      // or the row doesn't exist.
      if (count === 0) {
        throw new Error("You are not authorized to delete this post.");
      }
      return; // Success
    }

    // Handle Retryable Errors (Token Expiry)
    const isTokenError = error.status === 401 || 
                         error.code === 'PGRST301' || 
                         (error.message && error.message.includes("JWT"));

    if (isTokenError && attempts < maxAttempts) {
       console.log("[Echo] Token expired during delete. Refreshing session...");
       const { error: refreshErr } = await supabase.auth.refreshSession();
       if (!refreshErr) continue; // Loop again with new token
    }

    // Handle Permission Errors explicitly
    if (error.status === 403 || error.code === '42501') {
       throw new Error("You are not authorized to delete this post.");
    }

    // Throw other errors
    throw new Error(formatError(error));
  }
};

