/**
 * Deletes a post safely using the authenticated session.
 * STRICT SECURITY: Shadow Mode (client-side header auth) is disabled for deletions.
 */
export const deletePost = async (id: string): Promise<void> => {
  if (!id) throw new Error("Invalid Post ID");

  // 1. Get Session
  const { data: { session } } = await supabase.auth.getSession();

  // 2. Gatekeeping: Require real authentication
  if (!session?.user) {
      if (isUsingShadowMode) {
          throw new Error("Guest users cannot delete posts. Please sign in to verify ownership.");
      }
      throw new Error("Please sign in to delete this post.");
  }

  // 3. Helper to execute the delete with exact count
  const executeDelete = async () => {
      return await supabase
        .from('posts')
        .delete({ count: 'exact' })
        .eq('id', id);
  };

  // 4. Attempt Delete (Attempt 1)
  let { error, count } = await executeDelete();

  // 5. Retry Logic: If 401/JWT error, refresh and try once more
  if (error) {
      const isAuthError = error.status === 401 || 
                          error.code === 'PGRST301' || 
                          (error.message && error.message.includes("JWT"));

      if (isAuthError) {
          console.log("[Echo] Token expired. Refreshing session...");
          const { error: refreshError } = await supabase.auth.refreshSession();
          if (!refreshError) {
              const retry = await executeDelete();
              error = retry.error;
              count = retry.count;
          }
      }
  }

  // 6. Final Error Handling
  if (error) {
      if (error.status === 403 || error.code === '42501') {
          throw new Error("You are not authorized to delete this post.");
      }
      throw new Error(formatError(error));
  }

  // 7. Success Validation (Row Level Security Check)
  if (count === 0) {
      // The query succeeded (200 OK), but deleted 0 rows.
      // This means either the post doesn't exist OR RLS filtered it out because the user doesn't own it.
      throw new Error("Unable to delete: post not found or you are not authorized.");
  }
};

