export const fetchPosts = async (): Promise<Post[]> => {
  try {
    const { data, error } = await supabase
      .from('posts')
      .select(`
        *,
        comments (
          id,
          content,
          body,
          nickname,
          avatar_seed,
          user_id,
          created_at
        )
      `)
      .order('created_at', { ascending: false })
      .limit(MAX_POSTS_LIMIT);

    if (error) throw error;
    return (data || []).map(mapRowToPost);
  } catch (error) {
    console.error("[Echo] Fetch Posts Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  // Validation
  if (!content || content.trim().length === 0) throw new Error("Content cannot be empty");
  if (content.length > 2000) throw new Error("Content exceeds 2000 characters");

  try {
    const { data, error } = await supabase
      .from('posts')
      .insert([{
        nickname,
        content,
        tags,
        avatar_seed: nickname,
        likes: 0
      }])
      .select()
      .single();

    if (error) throw error;

    cleanUpOldPosts(supabase);
    // Return post with empty comments array initially
    return mapRowToPost({ ...data, comments: [] });
  } catch (error) {
    console.error("[Echo] Create Post Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

/**
 * Deletes a post safely using the authenticated session.
 * 
 * Logic Flow:
 * 1. Resolve Identity: Get Session.
 * 2. If no session:
 *    - If Shadow Mode: Disallow (Security).
 *    - Else: Prompt Sign In.
 * 3. Perform Delete (exact count).
 * 4. If Error 401/JWT: Refresh Token & Retry Once.
 * 5. Check Results: 403 or Count 0 = Unauthorized.
 */
export const deletePost = async (id: string): Promise<void> => {
  if (!id) throw new Error("Invalid Post ID");

  // Step A: Resolve Identity Up-front
  const { data: { session } } = await supabase.auth.getSession();

  if (!session?.user) {
      if (isUsingShadowMode) {
          // Explicitly disallow insecure client-side shadow deletes
          throw new Error("Guest users cannot delete posts. Please sign in to verify ownership.");
      } else {
          // Not in shadow mode, but session missing? Must sign in.
          throw new Error("Please sign in to delete this post.");
      }
  }

  // Step B: Perform Delete (Authenticated Path)
  const executeDelete = async () => {
      return await supabase
        .from('posts')
        .delete({ count: 'exact' })
        .eq('id', id);
  };

  let { error, count } = await executeDelete();

  // Retry Logic: Handle Token Expiry
  if (error) {
      const isTokenError = error.status === 401 || 
                           error.code === 'PGRST301' || 
                           (error.message && error.message.includes("JWT"));

      if (isTokenError) {
          console.log("[Echo] Token expired. Refreshing session...");
          const { error: refreshError } = await supabase.auth.refreshSession();

          if (!refreshError) {
              // Retry once
              const retry = await executeDelete();
              error = retry.error;
              count = retry.count;
          }
      }
  }

  // Interpret Results
  if (error) {
      if (error.status === 403 || error.code === '42501') {
          throw new Error("You are not authorized to delete this post.");
      }
      throw new Error(formatError(error));
  }

  // Handle "Zero Rows Affected" (Success technically, but implies failure to user)
  if (count === 0) {
      throw new Error("Unable to delete the post: either it was removed already or you are not authorized.");
  }
};

