// Internal UUID Helper to avoid external dependency issues on CDN
const generateUUID = (): string => {
  if (typeof crypto !== 'undefined' && typeof crypto.randomUUID === 'function') {
    return crypto.randomUUID();
  }
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
    var r = Math.random() * 16 | 0, v = c == 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
};

const validateUUID = (uuid: string): boolean => {
  // Relaxed validation: just check if it's a string and roughly correct length
  if (!uuid || typeof uuid !== 'string') return false;
  return uuid.length > 30; 
};

// Helper to format errors consistently
const formatError = (error: any): string => {
  if (!error) return 'Unknown error occurred';
  if (error.message) return error.message;
  if (typeof error === 'string') return error;
  return JSON.stringify(error);
};

// --- 1. SHADOW IDENTITY (FALLBACK) ---
const getShadowIdentity = (): string => {
  if (typeof window === 'undefined') return '';
  let id = localStorage.getItem('shadow_user_id');
  if (!id) {
    id = generateUUID();
    localStorage.setItem('shadow_user_id', id);
  }
  return id;
};

export const SHADOW_USER_ID = getShadowIdentity();

// --- 2. INITIALIZE CLIENT ---
// Note: We keep the shadow header for CREATION compatibility in 'Shadow Mode' (if policies allow),
// but DELETE operations will strictly verify the JWT session below.
const supabase = createClient(SUPABASE_URL, SUPABASE_KEY, {
  global: {
    headers: {
      'x-shadow-user-id': SHADOW_USER_ID 
    }
  }
});

export const getSupabase = () => supabase;

// --- 3. AUTHENTICATION ---

// Tracks if we are forced to use the fallback identity (Shadow Mode) 
// because standard Anonymous Auth failed or is disabled.
let isUsingShadowMode = false;

// Expose status for UI checks
export const isGuest = () => isUsingShadowMode;

export const initializeAuth = async (): Promise<string> => {
  try {
    const { data: { session } } = await supabase.auth.getSession();

    if (session?.user) {
      console.log("[Echo] Restored valid session:", session.user.id);
      isUsingShadowMode = false;
      return session.user.id;
    }

    console.log("[Echo] Attempting Anonymous Sign-in...");
    const { data, error } = await supabase.auth.signInAnonymously();

    if (error) {
      // Check for specific anonymous auth disabled errors
      if (
        error.message.includes("Anonymous sign-ins are disabled") || 
        error.status === 400 || 
        error.code === 'anonymous_provider_disabled'
      ) {
        console.warn("[Echo] Anonymous Auth disabled. Switching to Shadow Mode.");
        isUsingShadowMode = true;
        return SHADOW_USER_ID;
      }
      throw error;
    }

    if (data.user) {
        isUsingShadowMode = false;
        return data.user.id;
    }

    // Fallback if no user returned
    isUsingShadowMode = true;
    return SHADOW_USER_ID;

  } catch (e: any) {
    console.error("[Echo] Auth initialization error (using Shadow Mode):", formatError(e));
    isUsingShadowMode = true;
    return SHADOW_USER_ID;
  }
};

export const getEffectiveUserId = async (): Promise<string> => {
  const { data: { session } } = await supabase.auth.getSession();
  if (session?.user) {
      return session.user.id;
  }
  return SHADOW_USER_ID;
};

// --- DATA MAPPING ---

const mapRowToComment = (row: any): Comment => ({
  id: row.id,
  author: {
    nickname: row.nickname || 'Anonymous', // Fallback if column missing (though query will fail first)
    avatarSeed: row.avatar_seed || row.nickname || 'default',
    isAi: false, 
    userId: row.user_id
  },
  content: row.content || row.body || '', // Handle legacy 'body' column
  timestamp: new Date(row.created_at).getTime(),
  likes: 0 
});

const mapRowToPost = (row: any): Post => ({
  id: row.id,
  author: {
    nickname: row.nickname,
    avatarSeed: row.avatar_seed,
    isAi: false,
    userId: row.user_id 
  },
  content: row.content,
  tags: row.tags || [],
  timestamp: new Date(row.created_at).getTime(),
  likes: row.likes,
  comments: (row.comments || []).map(mapRowToComment).sort((a: Comment, b: Comment) => a.timestamp - b.timestamp)
});

// --- API METHODS ---

export const fetchPosts = async (): Promise<Post[]> => {
  try {
    const { data, error } = await supabase
      .from('posts')
      .select(`
        *,
        comments (
          id,
          content,
          body,
          nickname,
          avatar_seed,
          user_id,
          created_at
        )
      `)
      .order('created_at', { ascending: false })
      .limit(MAX_POSTS_LIMIT);

    if (error) throw error;
    return (data || []).map(mapRowToPost);
  } catch (error) {
    console.error("[Echo] Fetch Posts Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

export const createPost = async (nickname: string, content: string, tags: string[]): Promise<Post | null> => {
  // Validation
  if (!content || content.trim().length === 0) throw new Error("Content cannot be empty");
  if (content.length > 2000) throw new Error("Content exceeds 2000 characters");

  try {
    const { data, error } = await supabase
      .from('posts')
      .insert([{
        nickname,
        content,
        tags,
        avatar_seed: nickname,
        likes: 0
      }])
      .select()
      .single();

    if (error) throw error;

    cleanUpOldPosts(supabase);
    // Return post with empty comments array initially
    return mapRowToPost({ ...data, comments: [] });
  } catch (error) {
    console.error("[Echo] Create Post Failed:", formatError(error));
    throw new Error(formatError(error));
  }
};

/**
 * Deletes a post safely using the authenticated session.
 * 
 * Logic Flow:
 * 1. Resolve Identity: Get Session.
 * 2. If no session:
 *    - If Shadow Mode: Disallow (Security).
 *    - Else: Prompt Sign In.
 * 3. Perform Delete (exact count).
 * 4. If Error 401/JWT: Refresh Token & Retry Once.
 * 5. Check Results: 403 or Count 0 = Unauthorized.
 */
export const deletePost = async (id: string): Promise<void> => {
  if (!id) throw new Error("Invalid Post ID");

  // Step A: Resolve Identity Up-front
  const { data: { session } } = await supabase.auth.getSession();

  if (!session?.user) {
      if (isUsingShadowMode) {
          // Explicitly disallow insecure client-side shadow deletes
          throw new Error("Guest users cannot delete posts. Please sign in to verify ownership.");
      } else {
          // Not in shadow mode, but session missing? Must sign in.
          throw new Error("Please sign in to delete this post.");
      }
  }

  // Step B: Perform Delete (Authenticated Path)
  const executeDelete = async () => {
      return await supabase
        .from('posts')
        .delete({ count: 'exact' })
        .eq('id', id);
  };

  let { error, count } = await executeDelete();

  // Retry Logic: Handle Token Expiry
  if (error) {
      const isTokenError = error.status === 401 || 
                           error.code === 'PGRST301' || 
                           (error.message && error.message.includes("JWT"));

      if (isTokenError) {
          console.log("[Echo] Token expired. Refreshing session...");
          const { error: refreshError } = await supabase.auth.refreshSession();

          if (!refreshError) {
              // Retry once
              const retry = await executeDelete();
              error = retry.error;
              count = retry.count;
          }
      }
  }

  // Interpret Results
  if (error) {
      if (error.status === 403 || error.code === '42501') {
          throw new Error("You are not authorized to delete this post.");
      }
      throw new Error(formatError(error));
  }

  // Handle "Zero Rows Affected" (Success technically, but implies failure to user)
  if (count === 0) {
      throw new Error("Unable to delete the post: either it was removed already or you are not authorized.");
  }
};

